function handleStripeCheckoutSuccessLanding(query, res) {
  return sendHTML(res, 200, buildStripeCheckoutSuccessLandingHtml(query));
}

function handleStripeCheckoutCancelLanding(query, res) {
  return sendHTML(res, 200, buildStripeCheckoutCancelLandingHtml(query));
}

function stripeCheckoutLandingPathFromEnvUrl(rawUrl) {
  if (!rawUrl) return null;
  try {
    const u = new URL(rawUrl);
    const p = u.pathname.replace(/\/+$/, '') || '/';
    return p;
  } catch (_) {
    return null;
  }
}

function isStripeCheckoutSuccessLandingPath(pathname, query) {
  if (pathname === '/staff/payment/success' || pathname === '/staff/stripe/success') return true;
  if (pathname === '/staff' && query && query.session_id) return true;
  return false;
}

function isStripeCheckoutCancelLandingPath(pathname, query) {
  if (pathname === '/staff/payment/cancel' || pathname === '/staff/stripe/cancel') return true;
  if (pathname === '/staff' && !(query && query.session_id)) return true;
  return false;
}

const GUEST_PAY_SHORT_LINK_RE = /^\/pay\/([^/]+)(?:\/g(\d+))?$/i;

function requestPrefersJson(req) {
  const accept = String((req && req.headers && req.headers.accept) || '').toLowerCase();
  return accept.includes('application/json');
}

function buildGuestPaymentLinkStatusHtml(title, message) {
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${title}</title>
  <style>
    body { font-family: system-ui, sans-serif; background: #f6f8fb; color: #1a1a1a; margin: 0; padding: 32px 16px; }
    .card { max-width: 520px; margin: 0 auto; background: #fff; border-radius: 12px; padding: 28px 24px; box-shadow: 0 8px 24px rgba(0,0,0,.06); }
    h1 { font-size: 1.25rem; margin: 0 0 12px; }
    p { margin: 0; line-height: 1.5; color: #444; }
  </style>
</head>
<body>
  <div class="card">
    <h1>${title}</h1>
    <p>${message}</p>
  </div>
</body>
</html>`;
}

function sendGuestPaymentLinkStatus(res, statusCode, payload, req) {
  const body = payload || {};
  if (requestPrefersJson(req)) {
    return sendJSON(res, statusCode, {
      success: statusCode >= 200 && statusCode < 300,
      status: body.status || null,
      message: body.message || null,
      booking_code: body.booking_code || null,
      payment_short_url: body.payment_short_url || null,
      stripe_checkout_url_present: body.stripe_checkout_url_present === true,
      stripe_session_id: body.stripe_session_id || null,
    });
  }
  const title = statusCode === 200 ? 'Payment link' : 'Payment link unavailable';
  return sendHTML(res, statusCode, buildGuestPaymentLinkStatusHtml(title, body.message || 'Payment link unavailable.'));
}

/**
 * Stage 37c — GET /pay/:bookingCode
 * Read-only redirect to existing Stripe checkout URL. Never creates sessions or marks paid.
 */
async function handleGuestPaymentShortLinkRedirect(bookingCodeToken, guestNumberToken, parsedQuery, req, res) {
  const compositeToken = guestNumberToken
    ? `${bookingCodeToken}/g${guestNumberToken}`
    : bookingCodeToken;
  const parsed = parsePaymentShortLinkToken(compositeToken);
  if (!parsed.ok) {
    return sendGuestPaymentLinkStatus(res, 404, {
      status: 'invalid_token',
      message: 'This payment link is not valid.',
    }, req);
  }

  const clientSlug = (parsedQuery.client != null ? String(parsedQuery.client).trim() : '')
    || (process.env.DEFAULT_CLIENT_SLUG != null ? String(process.env.DEFAULT_CLIENT_SLUG).trim() : '')
    || 'wolfhouse-somo';

  let outcome;
  try {
    outcome = await withPgClient((pg) => resolvePaymentShortLinkRedirectFromDb(pg, {
      booking_code: parsed.booking_code,
      guest_number: parsed.guest_number,
      client_slug: clientSlug,
      env: process.env,
    }));
  } catch (err) {
    return sendGuestPaymentLinkStatus(res, 500, {
      status: 'error',
      message: 'We could not open this payment link right now. Please message Wolfhouse and we\'ll send a fresh one.',
    }, req);
  }

  if (outcome.status === 'redirect' && outcome.redirect_url) {
    res.writeHead(302, {
      Location: outcome.redirect_url,
      'Cache-Control': 'no-store',
      'X-Powered-By': 'wolfhouse-staff-api/payment-short-link',
    });
    return res.end();
  }

  const statusCode = outcome.status === 'paid' ? 200
    : outcome.status === 'unsafe_live' ? 503
      : 404;

  return sendGuestPaymentLinkStatus(res, statusCode, outcome, req);
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: GET /staff/intents
// ─────────────────────────────────────────────────────────────────────────────

function handleIntents(res) {
  const grouped = {};
  for (const cat of CATEGORIES) {
    grouped[cat] = REGISTRY
      .filter((e) => e.category === cat)
      .map((e) => ({
        key:              e.key,
        description:      e.description,
        requiredParams:   e.requiredParams.map((p) => p.name),
        optionalParams:   e.optionalParams.map((p) => p.name),
        migrationRequired: e.migrationRequired || null,
      }));
  }
  sendJSON(res, 200, {
    success:    true,
    categories: CATEGORIES,
    intents:    grouped,
    total:      REGISTRY.length,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: GET /staff/query
// ─────────────────────────────────────────────────────────────────────────────

async function handleQuery(query, res) {
  const started    = Date.now();
  const intentKey  = (query.intent || '').trim();
  const clientSlug = (query.client || DEFAULT_CLIENT).trim();

  // Validate client slug
  if (SQL_INJECT_RE.test(clientSlug)) {
    return send400(res, 'invalid client slug');
  }

  // Intent must be provided
  if (!intentKey) {
    return send400(res, 'missing required param: intent');
  }

  // Intent must be in registry
  const entry = getEntry(intentKey);
  if (!entry) {
    return send400(res, `unknown intent: '${intentKey}' — see GET /staff/intents for allowlist`);
  }

  // Safety guards
  if (entry.readOnly !== true || entry.clientSlugged !== true) {
    return send400(res, `intent '${intentKey}' is not safe for API execution`);
  }
  if (entry.missingHelper === true || typeof entry.helperRef !== 'function') {
    return send400(res, `intent '${intentKey}' has no query helper implemented yet`);
  }

  // Resolve params
  const { params, used, missing } = resolveParams(entry, clientSlug, query);
  if (missing.length > 0) {
    return send400(res, `missing required params: ${missing.join(', ')}`);
  }

  // Execute
  let rows = [];
  let success = true;
  let errorMsg = null;
  try {
    const sql = entry.helperRef();
    rows = await withPgClient(async (client) => {
      const result = await client.query(sql, params);
      return result.rows;
    });
  } catch (err) {
    success  = false;
    errorMsg = err.message;
    appendAuditLog({
      ts:          new Date().toISOString(),
      intent:      `api:${intentKey}`,
      category:    'staff_api',
      client_slug: clientSlug,
      params:      used,
      row_count:   0,
      success:     false,
      error:       errorMsg,
      elapsed_ms:  Date.now() - started,
    });
    return sendJSON(res, 500, { success: false, error: 'query execution failed', detail: null });
  }

  // Apply optional limit
  const limit = parseInt(query.limit, 10);
  const sliced = (!isNaN(limit) && limit > 0) ? rows.slice(0, Math.min(limit, MAX_ROWS)) : rows.slice(0, MAX_ROWS);

  const elapsed = Date.now() - started;
  appendAuditLog({
    ts:          new Date().toISOString(),
    intent:      `api:${intentKey}`,
    category:    'staff_api',
    client_slug: clientSlug,
    params:      used,
    row_count:   rows.length,
    success:     true,
    error:       null,
    elapsed_ms:  elapsed,
  });

  sendJSON(res, 200, {
    success:         true,
    intent:          intentKey,
    category:        entry.category,
    client_slug:     clientSlug,
    params:          used,
    row_count:       rows.length,
    rows_returned:   sliced.length,
    rows:            sliced,
    elapsed_ms:      elapsed,
    migration_note:  entry.migrationRequired || null,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: POST /staff/ask-luna  (Stage 8.6.1 — staff operational query via text)
//
// Accepts a natural-language staff question, resolves it to a registry intent,
// executes the query read-only, and returns a concise WhatsApp-friendly answer.
//
// Auth:
//   source=staff_portal  → requireAuth session (viewer+)
//   source=staff_whatsapp → staff_phone must be in STAFF_ALLOWLIST_FILE
//                           AND staff_whatsapp_enabled:true in config
//                           AND entry.active:true
//
// Safety:
//   read_only: true
//   no_write_performed: true
//   sends_whatsapp: false
//   no INSERT / UPDATE / DELETE
// ─────────────────────────────────────────────────────────────────────────────

const {
  executeStaffAskLunaQuestion,
  resolveAskLunaIntent,
} = require('./lib/staff-ask-luna-execute');
const {
  validateOwnerReadOnlySql,
  executeOwnerReadOnlySql,
} = require('./lib/owner-readonly-sql');
const { planOwnerSqlQuestion } = require('./lib/owner-sql-planner');
const { planAndExecuteOwnerSqlQuestion } = require('./lib/owner-sql-plan-execute');

function handleAskLunaAiStatus(res) {
  const diag = resolveLunaAiDiagnostics(process.env);
  return sendJSON(res, 200, {
    success:            true,
    configured:         diag.enabled,
    provider:           diag.provider,
    model:              diag.model,
    key_present:        diag.key_present,
    key_source:         diag.key_source,
    key_length:         diag.key_length,
    key_fingerprint:    diag.key_fingerprint,
    provider_source:    diag.provider_source,
    model_source:       diag.model_source,
    read_only:          true,
    no_write_performed: true,
  });
}

async function handleAskLuna(req, res) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const source     = String(body.source      || 'staff_portal').trim();
  const staffPhone = body.staff_phone ? String(body.staff_phone).trim() : null;
  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const question   = String(body.question    || '').trim();

  // ── Auth ──────────────────────────────────────────────────────────────────
  let staffAccess;
  // DB-backed access shape (role / owner_insights / allowed_categories) when the
  // number is recognized via the tenant-scoped DB allowlist; null otherwise.
  let staffWhatsappAccess = null;
  let staffWhatsappRecognition = null;

  if (source === 'staff_whatsapp') {
    // Phone-based auth: check allowlist config
    if (!staffPhone) {
      return sendJSON(res, 403, {
        success: false, error: 'staff_phone_required',
        detail:  'staff_phone is required for source=staff_whatsapp',
        sends_whatsapp: false,
      });
    }

    // DB-backed allowlist first (tenant-scoped by client_slug). Falls back to the
    // static JSON allowlist when the number is not found (or the table is absent).
    let dbEntry = null;
    try { dbEntry = await withPgClient((pg) => resolveStaffWhatsappEntry(pg, clientSlug, staffPhone)); } catch (_) { dbEntry = null; }

    if (dbEntry && dbEntry.found) {
      staffAccess = 'allowlisted_phone';
      staffWhatsappRecognition = 'db_number';
      staffWhatsappAccess = {
        role: dbEntry.role,
        owner_insights: dbEntry.owner_insights,
        allowed_categories: dbEntry.allowed_categories,
      };
    } else {
      let allowlist;
      try {
        allowlist = JSON.parse(fs.readFileSync(STAFF_ALLOWLIST_FILE, 'utf8'));
      } catch (_) {
        return sendJSON(res, 403, {
          success: false, error: 'allowlist_not_configured',
          detail:  'staff_whatsapp allowlist config not found',
          sends_whatsapp: false,
        });
      }

      if (!allowlist.staff_whatsapp_enabled) {
        return sendJSON(res, 403, {
          success: false, error: 'staff_whatsapp_disabled',
          detail:  'staff_whatsapp_enabled is false in allowlist config',
          sends_whatsapp: false,
        });
      }

      const entry = (allowlist.staff_numbers || []).find(
        (n) => n.phone === staffPhone && n.active === true
      );
      if (!entry) {
        return sendJSON(res, 403, {
          success: false, error: 'phone_not_allowlisted',
          detail:  'staff_phone is not in the active staff allowlist',
          sends_whatsapp: false,
        });
      }

      staffAccess = 'allowlisted_phone';
      staffWhatsappRecognition = 'json_allowlist';
    }

  } else {
    // Session auth for staff_portal (or any non-whatsapp source)
    const auth = await requireAuth(req, res, 'viewer');
    if (!auth.ok) return;
    staffAccess = 'session';
  }

  // ── Input validation ──────────────────────────────────────────────────────
  if (!question) return send400(res, 'question is required');
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');

  // ── Resolve intent (deterministic → optional AI registry classifier) ───────
  const askLunaLocationId = clientSlug === 'sunset'
    ? normalizeSunsetLocationId(body.location_id || body.location)
    : null;
  const result = await executeStaffAskLunaQuestion({
    client_slug: clientSlug,
    location_id: askLunaLocationId,
    question,
    source,
    staff_access: staffAccess,
    // Carry the DB-resolved access shape (owner vs operator) into execution when
    // the number was recognized via the tenant-scoped DB allowlist.
    ...(staffWhatsappAccess
      ? {
          role:               staffWhatsappAccess.role,
          owner_insights:     staffWhatsappAccess.owner_insights,
          allowed_categories: staffWhatsappAccess.allowed_categories,
        }
      : {}),
    ...(staffWhatsappRecognition ? { recognition: staffWhatsappRecognition } : {}),
  });

  if (!result.success) {
    const status = result.error === 'query_error' ? 500 : 400;
    return sendJSON(res, status, {
      success: false,
      error: result.error,
      detail: result.detail,
      sends_whatsapp: false,
    });
  }

  return sendJSON(res, 200, result);
}

// ── Stage 25d — Owner read-only SQL validate/execute (testing foundation) ───
async function handleOwnerSqlPlan(req, res, user) {
  let body = {};
  try {
    body = JSON.parse(await readBody(req) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const question = String(body.question || '').trim();
  if (!question) return send400(res, 'question is required');
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const result = await planOwnerSqlQuestion({
    client_slug: clientSlug,
    question,
    role: String(body.role || 'owner').trim() || 'owner',
    env: process.env,
  });

  const status = result.success ? 200 : 400;
  return sendJSON(res, status, result);
}

async function handleOwnerSqlValidate(req, res, user) {
  let body = {};
  try {
    body = JSON.parse(await readBody(req) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const sql = String(body.sql || '').trim();
  if (!sql) return send400(res, 'sql is required');
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const maxLimit = body.max_limit != null ? Number(body.max_limit) : undefined;
  const validation = validateOwnerReadOnlySql({
    sql,
    client_slug: clientSlug,
    maxLimit: Number.isFinite(maxLimit) && maxLimit > 0 ? maxLimit : undefined,
  });

  return sendJSON(res, validation.ok ? 200 : 400, {
    success: validation.ok,
    client_slug: clientSlug,
    validation,
    read_only: true,
    no_write_performed: true,
  });
}

async function handleOwnerSqlExecute(req, res, user) {
  let body = {};
  try {
    body = JSON.parse(await readBody(req) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const sql = String(body.sql || '').trim();
  if (!sql) return send400(res, 'sql is required');
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const params = Array.isArray(body.params) ? body.params : [];
  const maxRows = body.max_rows != null ? Number(body.max_rows) : undefined;
  const maxLimit = body.max_limit != null ? Number(body.max_limit) : undefined;
  const timeoutMs = body.timeout_ms != null ? Number(body.timeout_ms) : undefined;

  try {
    const result = await withPgClient((pg) => executeOwnerReadOnlySql(pg, {
      client_slug: clientSlug,
      sql,
      params,
      maxRows: Number.isFinite(maxRows) && maxRows > 0 ? maxRows : undefined,
      maxLimit: Number.isFinite(maxLimit) && maxLimit > 0 ? maxLimit : undefined,
      timeoutMs: Number.isFinite(timeoutMs) && timeoutMs > 0 ? timeoutMs : undefined,
    }));
    const status = result.success ? 200 : 400;
    return sendJSON(res, status, {
      ...result,
      client_slug: clientSlug,
    });
  } catch (err) {
    return sendJSON(res, 500, {
      success: false,
      error: 'query_error',
      detail: err.message,
      read_only: true,
      no_write_performed: true,
    });
  }
}

async function handleOwnerSqlPlanAndExecute(req, res, user) {
  let body = {};
  try {
    body = JSON.parse(await readBody(req) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  const question = String(body.question || '').trim();
  if (!question) return send400(res, 'question is required');
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const maxRows = body.max_rows != null ? Number(body.max_rows) : undefined;
  const maxLimit = body.max_limit != null ? Number(body.max_limit) : undefined;
  const timeoutMs = body.timeout_ms != null ? Number(body.timeout_ms) : undefined;

  try {
    const result = await withPgClient((pg) => planAndExecuteOwnerSqlQuestion(pg, {
      client_slug: clientSlug,
      question,
      role: String(body.role || 'owner').trim() || 'owner',
      maxRows: Number.isFinite(maxRows) && maxRows > 0 ? maxRows : undefined,
      maxLimit: Number.isFinite(maxLimit) && maxLimit > 0 ? maxLimit : undefined,
      timeoutMs: Number.isFinite(timeoutMs) && timeoutMs > 0 ? timeoutMs : undefined,
      env: process.env,
    }));
    return sendJSON(res, 200, result);
  } catch (err) {
    return sendJSON(res, 500, {
      success: false,
      error: 'owner_sql_plan_execute_failed',
      detail: 'Plan-and-execute failed',
      read_only: true,
      no_write_performed: true,
      no_query_executed: true,
    });
  }
}

// ─────────────────────────────────────────────────────────────────────────────

function readBody(req) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on('data', (chunk) => {
      chunks.push(chunk);
      if (Buffer.concat(chunks).length > 10240) req.destroy(new Error('body too large'));
    });
    req.on('end', () => resolve(Buffer.concat(chunks).toString('utf8')));
    req.on('error', reject);
  });
}
// Stage 8.4.11 — Raw Buffer variant required for Stripe webhook signature verification.
// Stripe's constructEvent() needs the exact raw bytes, not a parsed/re-serialised string.
function readBodyRaw(req, maxBytes) {
  const limit = maxBytes || 102400; // 100KB default
  return new Promise((resolve, reject) => {
    const chunks = [];
    let total = 0;
    req.on('data', (chunk) => {
      total += chunk.length;
      if (total > limit) { req.destroy(new Error('body too large')); return; }
      chunks.push(chunk);
    });
    req.on('end', () => resolve(Buffer.concat(chunks)));
    req.on('error', reject);
  });
}

async function handleResolveHandoff(handoffId, req, res) {
  const started = Date.now();

  // ── Feature flag gate ──────────────────────────────────────────────────────
  if (!STAFF_ACTIONS_ENABLED) {
    appendAuditLog({
      ts: new Date().toISOString(), intent: 'action:api:handoff.resolve',
      category: 'staff_write', handoff_id: handoffId,
      success: false, error: 'feature_flag_disabled', elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, {
      success: false,
      error: 'Staff write actions are disabled. Set STAFF_ACTIONS_ENABLED=true to enable.',
    });
  }

  // ── Auth gate (session when STAFF_AUTH_REQUIRED=true, else operator token) ──
  // Session path: requires authenticated session with role operator or admin.
  // Token path: local/dev backward compat (STAFF_AUTH_REQUIRED=false only).
  if (STAFF_AUTH_REQUIRED) {
    let sessionUser;
    try { sessionUser = await loadAuthSession(req); } catch (_) { sessionUser = null; }
    if (!sessionUser) {
      appendAuditLog({
        ts: new Date().toISOString(), intent: 'action:api:handoff.resolve',
        category: 'staff_write', handoff_id: handoffId,
        success: false, error: 'invalid_token', elapsed_ms: Date.now() - started,
      });
      return sendJSON(res, 401, {
        success: false,
        error: 'Authentication required for write actions when STAFF_AUTH_REQUIRED=true.',
      });
    }
    if (!hasRole(sessionUser.role, 'operator')) {
      appendAuditLog({
        ts: new Date().toISOString(), intent: 'action:api:handoff.resolve',
        category: 'staff_write', handoff_id: handoffId,
        success: false, error: 'insufficient_role', elapsed_ms: Date.now() - started,
      });
      return sendJSON(res, 403, {
        success:      false,
        error:        `Role 'operator' or higher required for handoff.resolve.`,
        current_role: sessionUser.role,
      });
    }
  } else {
    // Token gate (local/dev only — never used in staging/prod)
    const providedToken = (req.headers['x-staff-operator-token'] || '').trim();
    if (!STAFF_OPERATOR_TOKEN || !providedToken || providedToken !== STAFF_OPERATOR_TOKEN) {
      appendAuditLog({
        ts: new Date().toISOString(), intent: 'action:api:handoff.resolve',
        category: 'staff_write', handoff_id: handoffId,
        success: false, error: 'invalid_token', elapsed_ms: Date.now() - started,
      });
      return sendJSON(res, 401, { success: false, error: 'Missing or invalid x-staff-operator-token header.' });
    }
  }

  // ── Parse body ─────────────────────────────────────────────────────────────
  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = (String(body.client     || DEFAULT_CLIENT)).trim();
  const resolutionRaw  = String(body.resolution  || '').trim();
  const staffName      = String(body.staff       || 'Staff').trim().slice(0, 200);
  const confirmFlag    = body.confirm;

  // ── Validate body ──────────────────────────────────────────────────────────
  if (confirmFlag !== true) {
    return send400(res, 'confirm: true is required in request body');
  }
  if (!resolutionRaw) {
    return send400(res, 'resolution is required and must be non-empty');
  }
  if (SQL_INJECT_RE.test(resolutionRaw) || SQL_INJECT_RE.test(clientSlug)) {
    return send400(res, 'unsafe characters in request body');
  }
  const resolutionText = resolutionRaw.slice(0, 1000);

  const auditBase = {
    ts:          new Date().toISOString(),
    intent:      'action:api:handoff.resolve',
    category:    'staff_write',
    client_slug: clientSlug,
    handoff_id:  handoffId,
    staff:       staffName,
  };

  // ── Lookup target row ──────────────────────────────────────────────────────
  let handoff;
  try {
    handoff = await withPgClient(async (pgClient) => {
      const result = await pgClient.query(
        `SELECT h.id::text, h.status, h.reason_code, h.phone
         FROM staff_handoffs h
         JOIN clients c ON c.id = h.client_id
         WHERE h.id = $1::uuid AND c.slug = $2`,
        [handoffId, clientSlug]
      );
      return result.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: 'lookup_failed: ' + err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'handoff lookup failed' });
  }

  if (!handoff) {
    appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error:   `handoff ${handoffId} not found or client mismatch`,
    });
  }

  // ── Idempotency: already resolved/cancelled ────────────────────────────────
  if (handoff.status === 'resolved' || handoff.status === 'cancelled') {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, already_resolved: true, status_before: handoff.status, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success:          true,
      action:           'handoff.resolve',
      handoff_id:       handoffId,
      already_resolved: true,
      status_before:    handoff.status,
      status_after:     handoff.status,
      elapsed_ms:       elapsed,
    });
  }

  // ── Execute write ──────────────────────────────────────────────────────────
  let updated;
  try {
    const sql = resolveHandoffSql();
    updated = await withPgClient(async (pgClient) => {
      const result = await pgClient.query(sql, [clientSlug, handoffId, resolutionText]);
      return result.rows[0] || null;
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: 'write_failed: ' + err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'write failed' });
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success:       true,
    already_resolved: false,
    status_before: handoff.status,
    status_after:  'resolved',
    elapsed_ms:    elapsed,
  });

  return sendJSON(res, 200, {
    success:          true,
    action:           'handoff.resolve',
    handoff_id:       handoffId,
    status_before:    handoff.status,
    status_after:     'resolved',
    already_resolved: false,
    resolution:       resolutionText,
    staff:            staffName,
    resolved_at:      updated ? updated.resolved_at : null,
    elapsed_ms:       elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Route: POST /staff/manual-bookings/preview  (Stage 8.3h — read-only preview)
//
// Preview-only: no booking creation, no DB writes, no Stripe, no WhatsApp.
// Does NOT require STAFF_ACTIONS_ENABLED or MANUAL_BOOKING_ENABLED.
// Requires auth (operator/admin/owner when STAFF_AUTH_REQUIRED=true).
// ─────────────────────────────────────────────────────────────────────────────

async function handleManualBookingPreview(req, res, user) {
  const started = Date.now();

  // ── Parse body ─────────────────────────────────────────────────────────────
  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  // ── Extract and sanitise input ─────────────────────────────────────────────
  const clientSlug   = String(body.client || body.client_slug || DEFAULT_CLIENT).trim();
  const checkIn      = String(body.check_in  || '').trim();
  const checkOut     = String(body.check_out || '').trim();
  const guestCount   = parseInt(body.guest_count, 10) || 0;

  // selected_bed_codes: accept array or comma-separated string
  let rawBedCodes = body.selected_bed_codes;
  if (typeof rawBedCodes === 'string') {
    rawBedCodes = rawBedCodes.split(',').map((s) => s.trim()).filter(Boolean);
  } else if (!Array.isArray(rawBedCodes)) {
    rawBedCodes = [];
  }
  const selectedBedCodes = rawBedCodes.map(String).slice(0, 20); // max 20 beds

  // Optional fields (informational only — stored in audit, not used for query)
  const packageOrStayType   = String(body.package_or_stay_type   || '').trim().slice(0, 200);
  const roomPreference      = String(body.room_preference        || '').trim().slice(0, 200);
  const paymentStatus       = String(body.payment_status         || '').trim().slice(0, 50);
  const depositAmountCents  = parseInt(body.deposit_amount_cents,  10) || 0;
  const totalAmountCents    = parseInt(body.total_amount_cents,    10) || 0;

  // ── Input guards ───────────────────────────────────────────────────────────
  if (SQL_INJECT_RE.test(clientSlug))
    return send400(res, 'invalid client slug');
  if (!checkIn || !checkOut)
    return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
  if (!/^\d{4}-\d{2}-\d{2}$/.test(checkIn) || !/^\d{4}-\d{2}-\d{2}$/.test(checkOut))
    return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (selectedBedCodes.some((c) => SQL_INJECT_RE.test(c)))
    return send400(res, 'invalid character in selected_bed_codes');

  // ── Actor info ─────────────────────────────────────────────────────────────
  const actorId   = user ? user.staff_user_id : 'dev-preview-local';
  const actorRole = user ? user.role          : 'operator';

  const auditBase = {
    ts:                  new Date().toISOString(),
    intent:              'api:manual_booking_preview',
    category:            'manual_booking_preview',
    preview_only:        true,
    creates_booking:     false,
    no_write_performed:  true,
    client_slug:         clientSlug,
    check_in:            checkIn,
    check_out:           checkOut,
    selected_bed_codes:  selectedBedCodes,
    guest_count:         guestCount,
    staff_user_id:       actorId,
    staff_role:          actorRole,
  };

  // ── Load data from DB (SELECT only) ────────────────────────────────────────
  let clientRow, bedRows, assignmentRows;
  try {
    const result = await withPgClient(async (pg) => {
      // C. Verify client exists
      const clientResult = await pg.query(
        getClientIdBySlugQuery(),
        [clientSlug]
      );

      // A. Load bed metadata for selected beds
      const bedsResult = await pg.query(
        getManualBookingPreviewBedsQuery(),
        [clientSlug, selectedBedCodes.length > 0 ? selectedBedCodes : ['']]
      );

      // B. Load existing assignments overlapping the proposed range
      // If selected_bed_codes is empty the query will return zero rows safely.
      const assignmentsResult = await pg.query(
        getManualBookingPreviewAssignmentsQuery(),
        [
          clientSlug,
          checkIn,
          checkOut,
          selectedBedCodes.length > 0 ? selectedBedCodes : [''],
        ]
      );

      return {
        clientRow:       clientResult.rows[0]    || null,
        bedRows:         bedsResult.rows,
        assignmentRows:  assignmentsResult.rows,
      };
    });
    clientRow       = result.clientRow;
    bedRows         = result.bedRows;
    assignmentRows  = result.assignmentRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'preview data load failed', detail: err.message });
  }

  // ── Client not found ───────────────────────────────────────────────────────
  if (!clientRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'client_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success:            false,
      error:              'client not found',
      client_slug:        clientSlug,
      preview_only:       true,
      creates_booking:    false,
      no_write_performed: true,
    });
  }

  // ── Map DB rows to availability helper shapes ──────────────────────────────
  const beds = bedRows.map((row) => ({
    bed_code:  row.bed_code,
    room_code: row.room_code,
    active:    row.active,
    sellable:  row.sellable   != null ? row.sellable   : true,
    capacity:  row.capacity,
  }));

  const existingAssignments = assignmentRows.map((row) => ({
    booking_code:          row.booking_code,
    booking_status:        row.booking_status,
    assignment_status:     row.assignment_status,
    bed_code:              row.bed_code,
    room_code:             row.room_code,
    assignment_start_date: row.assignment_start_date,
    assignment_end_date:   row.assignment_end_date,
    guest_name:            row.guest_name || row.bed_guest_name,
  }));

  // ── Call pure availability helper ──────────────────────────────────────────
  let availability;
  try {
    availability = previewManualBookingAvailability({
      client_id:            clientRow.client_id,
      check_in:             checkIn,
      check_out:            checkOut,
      selected_bed_codes:   selectedBedCodes,
      guest_count:          guestCount,
      existing_assignments: existingAssignments,
      beds:                 beds,
      options: {
        today: new Date().toISOString().slice(0, 10),
      },
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: 'availability_helper_error: ' + err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'availability calculation failed' });
  }

  // ── Build audit entry ──────────────────────────────────────────────────────
  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success:         true,
    is_valid:        availability.is_valid,
    has_conflict:    availability.has_conflict,
    blocker_count:   availability.blockers.length,
    warning_count:   availability.warnings.length,
    proposed_nights: availability.proposed_nights,
    elapsed_ms:      elapsed,
  });

  // ── Build response ─────────────────────────────────────────────────────────
  return sendJSON(res, 200, {
    success:                 true,
    preview_only:            true,
    creates_booking:         false,
    no_write_performed:      true,
    staff_actions_enabled:   STAFF_ACTIONS_ENABLED,
    manual_booking_enabled:  MANUAL_BOOKING_ENABLED,
    client_slug:             clientSlug,
    input_summary: {
      check_in:             checkIn,
      check_out:            checkOut,
      selected_bed_codes:   selectedBedCodes,
      guest_count:          guestCount,
      package_or_stay_type: packageOrStayType || null,
      room_preference:      roomPreference    || null,
      payment_status:       paymentStatus     || null,
      deposit_amount_cents: depositAmountCents || null,
      total_amount_cents:   totalAmountCents  || null,
    },
    availability,
    next_step: MANUAL_BOOKING_ENABLED
      ? 'Manual booking creation is enabled. POST /staff/manual-bookings/create to create.'
      : 'Manual booking creation is disabled. Set MANUAL_BOOKING_ENABLED to true to enable.',
    elapsed_ms: elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.2 — Booking move preview (read-only; no writes)
//
// POST /staff/bookings/move-preview
//
// Preview whether an existing booking could move to a target bed/date span.
// SELECT-only — no UPDATE/INSERT/DELETE. No booking move write in this phase.
// ─────────────────────────────────────────────────────────────────────────────

const MOVE_PREVIEW_NON_BLOCKING_STATUSES = Object.freeze(['cancelled', 'expired']);

const MOVE_PREVIEW_BOOKING_BY_ID_SQL = `
SELECT
  b.id::text                AS booking_id,
  b.booking_code,
  b.guest_name,
  b.check_in::text          AS check_in,
  b.check_out::text         AS check_out,
  b.status::text            AS status,
  b.payment_status::text      AS payment_status,
  b.guest_count,
  b.primary_room_code
FROM bookings b
INNER JOIN clients c ON c.id = b.client_id
WHERE c.slug = $1
  AND b.id::text = $2
LIMIT 1
`;

const MOVE_PREVIEW_BOOKING_BY_CODE_SQL = `
SELECT
  b.id::text                AS booking_id,
  b.booking_code,
  b.guest_name,
  b.check_in::text          AS check_in,
  b.check_out::text         AS check_out,
  b.status::text            AS status,
  b.payment_status::text      AS payment_status,
  b.guest_count,
  b.primary_room_code
FROM bookings b
INNER JOIN clients c ON c.id = b.client_id
WHERE c.slug = $1
  AND b.booking_code = $2
LIMIT 1
`;

const MOVE_PREVIEW_BED_BY_ID_SQL = `
SELECT
  bd.id::text         AS bed_id,
  bd.bed_code,
  bd.bed_label,
  bd.active           AS active,
  bd.sellable         AS sellable,
  r.id::text          AS room_id,
  r.room_code,
  r.name              AS room_name
FROM beds bd
INNER JOIN rooms r   ON r.id = bd.room_id AND r.client_id = bd.client_id
INNER JOIN clients c ON c.id = bd.client_id
WHERE c.slug = $1
  AND bd.id::text = $2
LIMIT 1
`;

const MOVE_PREVIEW_TARGET_ASSIGNMENTS_SQL = `
SELECT
  bb.id::text                             AS booking_bed_id,
  bb.bed_code,
  b.id::text                              AS booking_id,
  b.booking_code,
  b.guest_name,
  b.status::text                          AS booking_status,
  b.assignment_status::text               AS assignment_status,
  bb.assignment_start_date::text          AS check_in,
  bb.assignment_end_date::text            AS check_out
FROM booking_beds bb
INNER JOIN bookings b ON b.id = bb.booking_id
INNER JOIN clients  c ON c.id = bb.client_id
WHERE c.slug = $1
  AND bb.bed_code = $2
  AND bb.assignment_start_date < $4::date
  AND bb.assignment_end_date   > $3::date
ORDER BY bb.assignment_start_date ASC
`;

/** Phase 10.3h.4 — bulk move target availability (SELECT-only). */
const MOVE_TARGETS_ALL_BEDS_SQL = `
SELECT
  bd.id::text         AS bed_id,
  bd.bed_code,
  bd.active           AS active,
  bd.sellable         AS sellable,
  r.id::text          AS room_id,
  r.room_code,
  r.name              AS room_name
FROM beds bd
INNER JOIN rooms r   ON r.id = bd.room_id AND r.client_id = bd.client_id
INNER JOIN clients c ON c.id = bd.client_id
WHERE c.slug = $1
ORDER BY r.room_code ASC NULLS LAST, bd.bed_code ASC NULLS LAST
`;

const MOVE_TARGETS_RANGE_ASSIGNMENTS_SQL = `
SELECT
  bb.bed_id::text                         AS bed_id,
  bb.id::text                             AS booking_bed_id,
  bb.bed_code,
  b.id::text                              AS booking_id,
  b.booking_code,
  b.guest_name,
  b.status::text                          AS booking_status,
  b.assignment_status::text               AS assignment_status,
  bb.assignment_start_date::text          AS check_in,
  bb.assignment_end_date::text            AS check_out
FROM booking_beds bb
INNER JOIN bookings b ON b.id = bb.booking_id
INNER JOIN clients  c ON c.id = bb.client_id
WHERE c.slug = $1
  AND bb.assignment_start_date < $3::date
  AND bb.assignment_end_date   > $2::date
ORDER BY bb.bed_id ASC, bb.assignment_start_date ASC
`;

function movePreviewNights(checkIn, checkOut) {
  const start = parseCalendarDate(checkIn);
  const end   = parseCalendarDate(checkOut);
  if (!start || !end || end <= start) return null;
  return Math.round((end - start) / 86400000);
}

/** Half-open overlap: existing.check_in < target.check_out && existing.check_out > target.check_in */
function movePreviewHalfOpenOverlaps(existingStart, existingEnd, targetCheckIn, targetCheckOut) {
  if (!existingStart || !existingEnd || !targetCheckIn || !targetCheckOut) return false;
  return existingStart < targetCheckOut && existingEnd > targetCheckIn;
}

function movePreviewIsBlockingAssignment(row) {
  const bookingStatus    = String(row.booking_status    || '').trim().toLowerCase();
  const assignmentStatus = String(row.assignment_status || '').trim().toLowerCase();
  if (MOVE_PREVIEW_NON_BLOCKING_STATUSES.includes(bookingStatus)) return false;
  if (assignmentStatus && MOVE_PREVIEW_NON_BLOCKING_STATUSES.includes(assignmentStatus)) return false;
  return true;
}

function movePreviewBookingSummary(row) {
  return {
    booking_id:      row.booking_id,
    booking_code:    row.booking_code,
    guest_name:      row.guest_name,
    check_in:        row.check_in,
    check_out:       row.check_out,
    status:          row.status,
    payment_status:  row.payment_status,
    guest_count:     row.guest_count != null ? Number(row.guest_count) : null,
    primary_room_code: row.primary_room_code || null,
  };
}

function moveWriteAssignmentSummary(row, bedRow) {
  return {
    booking_bed_id: row.booking_bed_id,
    bed_id:         row.bed_id,
    bed_code:       row.bed_code,
    room_code:      row.room_code || (bedRow && bedRow.room_code) || null,
    room_name:      bedRow && bedRow.room_name ? bedRow.room_name : null,
    check_in:       row.check_in,
    check_out:      row.check_out,
  };
}

function moveFormatAssignmentOptions(rows) {
  return rows.map((row) => ({
    booking_bed_id: row.booking_bed_id,
    bed_id:         row.bed_id,
    bed_code:       row.bed_code,
    room_code:      row.room_code || null,
    check_in:       row.check_in,
    check_out:      row.check_out,
  }));
}

/** Phase 10.3g — resolve which booking_beds row to move (single infer, multi select, zero manual). */
function moveResolveSourceBed(sourceBeds, bookingBedId) {
  const id = String(bookingBedId || '').trim();
  if (sourceBeds.length === 0) {
    return {
      status:  'manual_review',
      reason:  'single_bed_booking_required',
      message: 'This booking has multiple or no active bed assignments and requires manual review.',
    };
  }
  if (sourceBeds.length > 1 && !id) {
    return {
      status:      'requires_selection',
      reason:      'booking_bed_selection_required',
      message:     'Select which bed assignment to move.',
      assignments: moveFormatAssignmentOptions(sourceBeds),
    };
  }
  let sourceBed = null;
  if (id) {
    sourceBed = sourceBeds.find((b) => b.booking_bed_id === id) || null;
    if (!sourceBed) {
      return {
        status:     'invalid_id',
        error:      'booking_bed_id not found for this booking',
        httpStatus: 400,
      };
    }
  } else {
    sourceBed = sourceBeds[0];
  }
  return { status: 'ok', sourceBed };
}

function moveWriteBuildConflicts(assignmentRows, excludeBookingBedId, checkIn, checkOut, bedRow) {
  const excludeId = String(excludeBookingBedId || '');
  return assignmentRows
    .filter((row) => row.booking_bed_id !== excludeId)
    .filter(movePreviewIsBlockingAssignment)
    .filter((row) => movePreviewHalfOpenOverlaps(row.check_in, row.check_out, checkIn, checkOut))
    .map((row) => ({
      booking_id:   row.booking_id,
      booking_code: row.booking_code,
      guest_name:   row.guest_name,
      check_in:     row.check_in,
      check_out:    row.check_out,
      bed_id:       bedRow.bed_id,
    }));
}

/** Phase 10.3h.4 — build per-bed availability for move-targets (half-open overlap). */
function moveBuildTargetAvailability(allBeds, assignmentRows, sourceBed, checkIn, checkOut) {
  const excludeId = sourceBed ? sourceBed.booking_bed_id : '';
  const sourceBedId = sourceBed ? sourceBed.bed_id : '';
  const byBed = new Map();
  for (const row of assignmentRows) {
    const bid = row.bed_id;
    if (!byBed.has(bid)) byBed.set(bid, []);
    byBed.get(bid).push(row);
  }
  const targets = allBeds.map((bed) => {
    const base = {
      bed_id:    bed.bed_id,
      bed_code:  bed.bed_code,
      room_id:   bed.room_id,
      room_code: bed.room_code,
      room_name: bed.room_name || null,
      is_current_source: bed.bed_id === sourceBedId,
      conflicts: [],
    };
    if (bed.bed_id === sourceBedId) {
      return {
        ...base,
        available: false,
        disabled_reason: 'current_source_bed',
      };
    }
    if (bed.active === false || bed.sellable === false) {
      return {
        ...base,
        available: false,
        disabled_reason: 'inactive',
      };
    }
    const conflicts = moveWriteBuildConflicts(
      byBed.get(bed.bed_id) || [],
      excludeId,
      checkIn,
      checkOut,
      bed
    );
    if (conflicts.length > 0) {
      return {
        ...base,
        available: false,
        disabled_reason: 'occupied',
        conflicts,
      };
    }
    return {
      ...base,
      available: true,
    };
  });
  targets.sort((a, b) => {
    if (a.available !== b.available) return a.available ? -1 : 1;
    const ak = (a.room_code || '') + '/' + (a.bed_code || '');
    const bk = (b.room_code || '') + '/' + (b.bed_code || '');
    return ak.localeCompare(bk);
  });
  return targets;
}

const MOVE_WRITE_SOURCE_BEDS_SQL = `
SELECT
  bb.id::text                             AS booking_bed_id,
  bb.bed_id::text                         AS bed_id,
  bb.bed_code,
  bb.room_code,
  bb.assignment_type,
  bb.assignment_start_date::text          AS check_in,
  bb.assignment_end_date::text            AS check_out
FROM booking_beds bb
INNER JOIN bookings b ON b.id = bb.booking_id
INNER JOIN clients  c ON c.id = bb.client_id
WHERE c.slug = $1
  AND b.id = $2::uuid
ORDER BY bb.assignment_start_date ASC
`;

const MOVE_WRITE_UPDATE_BED_SQL = `
UPDATE booking_beds bb
SET
  bed_id     = $1::uuid,
  bed_code   = $2,
  room_code  = $3,
  updated_at = NOW()
FROM clients c
WHERE bb.id = $4::uuid
  AND bb.client_id = c.id
  AND c.slug = $5
  AND bb.booking_id = $6::uuid
RETURNING
  bb.id::text                    AS booking_bed_id,
  bb.bed_id::text                AS bed_id,
  bb.bed_code,
  bb.room_code,
  bb.assignment_start_date::text AS check_in,
  bb.assignment_end_date::text   AS check_out
`;

/** Phase 10.3g — booking context rooming includes bed_id + check_in/out aliases for move UI. */
const BOOKING_CONTEXT_ROOMING_SQL = `
SELECT
  bb.id::text               AS booking_bed_id,
  bb.bed_id::text           AS bed_id,
  bb.room_code,
  bb.bed_code,
  bb.assignment_start_date::text AS assignment_start_date,
  bb.assignment_end_date::text   AS assignment_end_date,
  bb.assignment_start_date::text AS check_in,
  bb.assignment_end_date::text   AS check_out,
  bb.planning_row_label,
  bb.assignment_label,
  bb.assignment_type,
  bb.guest_name             AS bed_guest_name,
  r.name                    AS room_name,
  r.room_type,
  r.gender_strategy,
  r.capacity
FROM booking_beds bb
INNER JOIN bookings b ON b.id = bb.booking_id
INNER JOIN clients c ON c.id = b.client_id
LEFT JOIN beds bd ON bd.id = bb.bed_id
LEFT JOIN rooms r ON r.id = bd.room_id
WHERE c.slug = $1
  AND b.booking_code = $2
ORDER BY bb.assignment_start_date ASC, bb.room_code ASC
`;

async function handleBookingMoveWrite(req, res, user) {
  const started = Date.now();

  if (!BOOKING_MOVE_WRITE_ENABLED) {
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:booking_move',
      category: 'booking_move_write',
      success: false,
      error: 'booking_move_write_disabled',
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 403, {
      success: false,
      enabled: false,
      error: 'booking_move_write_disabled',
      moved: false,
      would_mutate: false,
    });
  }

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug     = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId      = String(body.booking_id   || '').trim();
  const bookingCode    = String(body.booking_code || '').trim();
  const targetBedId    = String(body.target_bed_id || '').trim();
  const targetRoomId   = String(body.target_room_id || '').trim();
  const bookingBedId   = String(body.booking_bed_id || '').trim();
  const checkIn        = String(body.check_in  || '').trim();
  const checkOut       = String(body.check_out || '').trim();
  const idempotencyKey = String(body.idempotency_key || '').trim();
  const reason         = String(body.reason || '').trim().slice(0, 500) || null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (bookingBedId && !UUID_VALIDATE_RE.test(bookingBedId)) return send400(res, 'booking_bed_id must be a valid UUID');
  if (!targetBedId) return send400(res, 'target_bed_id is required');
  if (!UUID_VALIDATE_RE.test(targetBedId)) return send400(res, 'target_bed_id must be a valid UUID');
  if (targetRoomId && !UUID_VALIDATE_RE.test(targetRoomId)) return send400(res, 'target_room_id must be a valid UUID');
  if (!checkIn || !checkOut) return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
  if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (!parseCalendarDate(checkIn) || !parseCalendarDate(checkOut)) return send400(res, 'check_in and check_out must be valid dates');
  if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');
  if (!idempotencyKey) return send400(res, 'idempotency_key is required');

  const actorId    = user ? user.staff_user_id : 'dev-move-write-local';
  const actorRole  = user ? user.role          : 'operator';
  const actorLabel = user ? (user.email || user.staff_user_id) : actorId;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:booking_move',
    category:        'booking_move_write',
    preview_only:    false,
    would_mutate:    true,
    client_slug:     clientSlug,
    booking_id:      bookingId || null,
    booking_code:    bookingCode || null,
    target_bed_id:   targetBedId,
    booking_bed_id:  bookingBedId || null,
    check_in:        checkIn,
    check_out:       checkOut,
    idempotency_key: idempotencyKey,
    staff_user_id:   actorId,
    staff_role:      actorRole,
    reason,
  };

  let bookingRow, bedRow, sourceBeds;
  try {
    const result = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? MOVE_PREVIEW_BOOKING_BY_ID_SQL : MOVE_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) {
        return { bookingRow: null, bedRow: null, sourceBeds: [] };
      }
      const bedRes = await pg.query(MOVE_PREVIEW_BED_BY_ID_SQL, [clientSlug, targetBedId]);
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]);
      return {
        bookingRow: booking,
        bedRow:     bedRes.rows[0] || null,
        sourceBeds: bedsRes.rows,
      };
    });
    bookingRow  = result.bookingRow;
    bedRow      = result.bedRow;
    sourceBeds  = result.sourceBeds;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'move write query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'booking not found', moved: false, would_mutate: false });
  }

  if (!bedRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'target_bed_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, { success: false, error: 'target bed not found', moved: false, would_mutate: false });
  }

  if (targetRoomId && bedRow.room_id !== targetRoomId) {
    appendAuditLog({ ...auditBase, success: false, error: 'target_room_mismatch', elapsed_ms: Date.now() - started });
    return sendJSON(res, 400, {
      success: false,
      error: 'target_room_id does not match the target bed room',
      moved: false,
      would_mutate: false,
    });
  }

  if (checkIn !== bookingRow.check_in || checkOut !== bookingRow.check_out) {
    appendAuditLog({ ...auditBase, success: false, error: 'date_change_not_supported_in_phase_10_3', elapsed_ms: Date.now() - started });
    return sendJSON(res, 400, {
      success: false,
      moved: false,
      can_move: false,
      error: 'date_change_not_supported_in_phase_10_3',
      message: 'Date changes are not supported in Phase 10.3. Request dates must match the booking stay.',
      would_mutate: false,
    });
  }

  // Phase 10.3g: zero beds → single_bed_booking_required; sourceBeds.length !== 1 → requires_selection
  const resolvedWrite = moveResolveSourceBed(sourceBeds, bookingBedId);
  if (resolvedWrite.status === 'requires_selection') {
    appendAuditLog({
      ...auditBase,
      success: true,
      moved: false,
      can_move: false,
      requires_selection: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 200, {
      success: true,
      moved: false,
      can_move: false,
      preview_only: false,
      would_mutate: false,
      requires_selection: true,
      reason: resolvedWrite.reason,
      assignments: resolvedWrite.assignments,
      booking: movePreviewBookingSummary(bookingRow),
      message: resolvedWrite.message,
    });
  }
  if (resolvedWrite.status === 'manual_review') {
    appendAuditLog({
      ...auditBase,
      success: true,
      moved: false,
      can_move: false,
      requires_manual_review: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 200, {
      success: true,
      moved: false,
      can_move: false,
      requires_manual_review: true,
      reason: resolvedWrite.reason,
      preview_only: false,
      would_mutate: false,
      booking: movePreviewBookingSummary(bookingRow),
      message: resolvedWrite.message,
    });
  }
  if (resolvedWrite.status === 'invalid_id') {
    appendAuditLog({ ...auditBase, success: false, error: resolvedWrite.error, elapsed_ms: Date.now() - started });
    return sendJSON(res, resolvedWrite.httpStatus || 400, {
      success: false,
      error: resolvedWrite.error,
      moved: false,
      would_mutate: false,
    });
  }
  const sourceBed = resolvedWrite.sourceBed;
  if (sourceBed.check_in !== checkIn || sourceBed.check_out !== checkOut) {
    appendAuditLog({
      ...auditBase,
      success: true,
      moved: false,
      can_move: false,
      requires_manual_review: true,
      error: 'assignment_date_mismatch',
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 200, {
      success: true,
      moved: false,
      can_move: false,
      requires_manual_review: true,
      reason: 'assignment_date_mismatch',
      preview_only: false,
      would_mutate: false,
      booking: movePreviewBookingSummary(bookingRow),
      message: 'Assignment dates do not match the booking stay. Manual review required.',
    });
  }

  const previousAssignment = moveWriteAssignmentSummary(sourceBed, null);
  const sourceBookingId = bookingRow.booking_id;

  if (
    sourceBed.bed_id === bedRow.bed_id &&
    sourceBed.bed_code === bedRow.bed_code
  ) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, moved: false, idempotent: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      moved: false,
      idempotent: true,
      preview_only: false,
      would_mutate: false,
      booking: movePreviewBookingSummary(bookingRow),
      previous_assignment: previousAssignment,
      new_assignment: moveWriteAssignmentSummary(sourceBed, bedRow),
      audit: {
        actor: actorLabel,
        reason,
        idempotency_key: idempotencyKey,
      },
      message: 'Booking is already assigned to the requested bed/date range.',
      elapsed_ms: elapsed,
    });
  }

  if (bedRow.active === false || bedRow.sellable === false) {
    appendAuditLog({ ...auditBase, success: true, moved: false, can_move: false, error: 'target_bed_unavailable', elapsed_ms: Date.now() - started });
    return sendJSON(res, 200, {
      success: true,
      moved: false,
      can_move: false,
      preview_only: false,
      would_mutate: false,
      booking: movePreviewBookingSummary(bookingRow),
      conflicts: [],
      message: 'Target bed is not active or sellable. No changes were made.',
    });
  }

  try {
    const writeResult = await withPgClient(async (pg) => {
      await pg.query('BEGIN');
      try {
        const assignRes = await pg.query(
          MOVE_PREVIEW_TARGET_ASSIGNMENTS_SQL,
          [clientSlug, bedRow.bed_code, checkIn, checkOut]
        );
        const conflicts = moveWriteBuildConflicts(
          assignRes.rows,
          sourceBed.booking_bed_id,
          checkIn,
          checkOut,
          bedRow
        );
        if (conflicts.length > 0) {
          await pg.query('ROLLBACK');
          return { ok: false, conflicts };
        }

        const upd = await pg.query(MOVE_WRITE_UPDATE_BED_SQL, [
          bedRow.bed_id,
          bedRow.bed_code,
          bedRow.room_code,
          sourceBed.booking_bed_id,
          clientSlug,
          sourceBookingId,
        ]);
        if (!upd.rows[0]) {
          await pg.query('ROLLBACK');
          return { ok: false, error: 'update_failed' };
        }
        await pg.query('COMMIT');
        return { ok: true, newRow: upd.rows[0] };
      } catch (e) {
        try { await pg.query('ROLLBACK'); } catch (_) {}
        throw e;
      }
    });

    if (!writeResult.ok && writeResult.conflicts) {
      const elapsed = Date.now() - started;
      appendAuditLog({
        ...auditBase,
        success: true,
        moved: false,
        can_move: false,
        conflict_count: writeResult.conflicts.length,
        elapsed_ms: elapsed,
      });
      return sendJSON(res, 200, {
        success: true,
        moved: false,
        can_move: false,
        preview_only: false,
        would_mutate: false,
        booking: movePreviewBookingSummary(bookingRow),
        conflicts: writeResult.conflicts,
        message: 'Target bed is not available for this date range. No changes were made.',
        elapsed_ms: elapsed,
      });
    }

    if (!writeResult.ok) {
      appendAuditLog({ ...auditBase, success: false, error: writeResult.error || 'write_failed', elapsed_ms: Date.now() - started });
      return sendJSON(res, 500, { success: false, error: 'booking move write failed', moved: false });
    }

    const newAssignment = moveWriteAssignmentSummary(writeResult.newRow, bedRow);
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      moved: true,
      previous_bed_id: previousAssignment.bed_id,
      new_bed_id: newAssignment.bed_id,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      success: true,
      moved: true,
      preview_only: false,
      would_mutate: true,
      booking: movePreviewBookingSummary(bookingRow),
      previous_assignment: previousAssignment,
      new_assignment: newAssignment,
      audit: {
        actor: actorLabel,
        reason,
        idempotency_key: idempotencyKey,
      },
      message: 'Booking moved. No payment, service, or message changes were made.',
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'booking move write failed', detail: err.message, moved: false });
  }
}

// ── Phase 10.3h.4 — Bulk move target availability (SELECT-only) ───────────────
// POST /staff/bookings/move-targets
async function handleBookingMoveTargets(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug   = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId    = String(body.booking_id   || '').trim();
  const bookingCode  = String(body.booking_code || '').trim();
  const bookingBedId = String(body.booking_bed_id || '').trim();
  const checkIn      = String(body.check_in  || '').trim();
  const checkOut     = String(body.check_out || '').trim();

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (bookingBedId && !UUID_VALIDATE_RE.test(bookingBedId)) return send400(res, 'booking_bed_id must be a valid UUID');
  if (!checkIn || !checkOut) return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
  if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (!parseCalendarDate(checkIn) || !parseCalendarDate(checkOut)) return send400(res, 'check_in and check_out must be valid dates');
  if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');

  const actorId   = user ? user.staff_user_id : 'dev-preview-local';
  const actorRole = user ? user.role          : 'operator';

  const auditBase = {
    ts:             new Date().toISOString(),
    intent:         'api:booking_move_targets',
    category:       'booking_move_targets',
    preview_only:   true,
    would_mutate:   false,
    client_slug:    clientSlug,
    booking_id:     bookingId || null,
    booking_code:   bookingCode || null,
    booking_bed_id: bookingBedId || null,
    check_in:       checkIn,
    check_out:      checkOut,
    staff_user_id:  actorId,
    staff_role:     actorRole,
  };

  let bookingRow, sourceBeds, allBeds, assignmentRows;
  try {
    const result = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? MOVE_PREVIEW_BOOKING_BY_ID_SQL : MOVE_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) {
        return { bookingRow: null, sourceBeds: [], allBeds: [], assignmentRows: [] };
      }
      const [bedsRes, assignRes, sourceRes] = await Promise.all([
        pg.query(MOVE_TARGETS_ALL_BEDS_SQL, [clientSlug]),
        pg.query(MOVE_TARGETS_RANGE_ASSIGNMENTS_SQL, [clientSlug, checkIn, checkOut]),
        pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]),
      ]);
      return {
        bookingRow:     booking,
        sourceBeds:     sourceRes.rows,
        allBeds:        bedsRes.rows,
        assignmentRows: assignRes.rows,
      };
    });
    bookingRow     = result.bookingRow;
    sourceBeds     = result.sourceBeds;
    allBeds        = result.allBeds;
    assignmentRows = result.assignmentRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'move targets query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error: 'booking not found',
      preview_only: true,
      would_mutate: false,
    });
  }

  if (checkIn !== bookingRow.check_in || checkOut !== bookingRow.check_out) {
    appendAuditLog({ ...auditBase, success: false, error: 'date_change_not_supported_in_phase_10_3', elapsed_ms: Date.now() - started });
    return sendJSON(res, 400, {
      success: false,
      error: 'date_change_not_supported_in_phase_10_3',
      message: 'Date changes are not supported in Phase 10.3. Request dates must match the booking stay.',
      preview_only: true,
      would_mutate: false,
    });
  }

  const resolved = moveResolveSourceBed(sourceBeds, bookingBedId);
  if (resolved.status === 'requires_selection') {
    const elapsedSel = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      requires_selection: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: elapsedSel,
    });
    return sendJSON(res, 200, {
      success: true,
      preview_only: true,
      would_mutate: false,
      requires_selection: true,
      reason: resolved.reason,
      assignments: resolved.assignments,
      booking: movePreviewBookingSummary(bookingRow),
      message: resolved.message,
      elapsed_ms: elapsedSel,
    });
  }
  if (resolved.status === 'manual_review') {
    const elapsedMr = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      requires_manual_review: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: elapsedMr,
    });
    return sendJSON(res, 200, {
      success: true,
      preview_only: true,
      would_mutate: false,
      requires_manual_review: true,
      reason: resolved.reason,
      booking: movePreviewBookingSummary(bookingRow),
      message: resolved.message,
      elapsed_ms: elapsedMr,
    });
  }
  if (resolved.status === 'invalid_id') {
    appendAuditLog({ ...auditBase, success: false, error: resolved.error, elapsed_ms: Date.now() - started });
    return sendJSON(res, resolved.httpStatus || 400, {
      success: false,
      error: resolved.error,
      preview_only: true,
      would_mutate: false,
    });
  }

  const sourceBed = resolved.sourceBed;
  const targets = moveBuildTargetAvailability(allBeds, assignmentRows, sourceBed, checkIn, checkOut);
  const elapsed = Date.now() - started;
  appendAuditLog({
    ...auditBase,
    success: true,
    target_count: targets.length,
    available_count: targets.filter((t) => t.available).length,
    elapsed_ms: elapsed,
  });
  return sendJSON(res, 200, {
    success: true,
    preview_only: true,
    would_mutate: false,
    booking: movePreviewBookingSummary(bookingRow),
    source_assignment: moveWriteAssignmentSummary(sourceBed, null),
    targets,
    elapsed_ms: elapsed,
  });
}

async function handleBookingMovePreview(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug    = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId     = String(body.booking_id   || '').trim();
  const bookingCode   = String(body.booking_code || '').trim();
  const targetBedId   = String(body.target_bed_id || '').trim();
  const targetRoomId  = String(body.target_room_id || '').trim();
  const bookingBedId  = String(body.booking_bed_id || '').trim();
  const checkIn       = String(body.check_in  || '').trim();
  const checkOut      = String(body.check_out || '').trim();

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (bookingBedId && !UUID_VALIDATE_RE.test(bookingBedId)) return send400(res, 'booking_bed_id must be a valid UUID');
  if (!targetBedId) return send400(res, 'target_bed_id is required');
  if (!UUID_VALIDATE_RE.test(targetBedId)) return send400(res, 'target_bed_id must be a valid UUID');
  if (targetRoomId && !UUID_VALIDATE_RE.test(targetRoomId)) return send400(res, 'target_room_id must be a valid UUID');
  if (!checkIn || !checkOut) return send400(res, 'check_in and check_out are required (YYYY-MM-DD)');
  if (!DATE_RE.test(checkIn) || !DATE_RE.test(checkOut)) return send400(res, 'check_in and check_out must be YYYY-MM-DD');
  if (!parseCalendarDate(checkIn) || !parseCalendarDate(checkOut)) return send400(res, 'check_in and check_out must be valid dates');
  if (checkOut <= checkIn) return send400(res, 'check_out must be after check_in');

  const nights = movePreviewNights(checkIn, checkOut);
  const actorId   = user ? user.staff_user_id : 'dev-preview-local';
  const actorRole = user ? user.role          : 'operator';

  const auditBase = {
    ts:             new Date().toISOString(),
    intent:         'api:booking_move_preview',
    category:       'booking_move_preview',
    preview_only:   true,
    would_mutate:   false,
    client_slug:    clientSlug,
    booking_id:     bookingId || null,
    booking_code:   bookingCode || null,
    target_bed_id:  targetBedId,
    booking_bed_id: bookingBedId || null,
    check_in:       checkIn,
    check_out:      checkOut,
    staff_user_id:  actorId,
    staff_role:     actorRole,
  };

  let bookingRow, bedRow, sourceBeds, assignmentRows;
  try {
    const result = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? MOVE_PREVIEW_BOOKING_BY_ID_SQL : MOVE_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) {
        return { bookingRow: null, bedRow: null, sourceBeds: [], assignmentRows: [] };
      }
      const bedRes = await pg.query(MOVE_PREVIEW_BED_BY_ID_SQL, [clientSlug, targetBedId]);
      const bed = bedRes.rows[0] || null;
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]);
      let assignments = [];
      if (bed && bed.bed_code) {
        const assignRes = await pg.query(
          MOVE_PREVIEW_TARGET_ASSIGNMENTS_SQL,
          [clientSlug, bed.bed_code, checkIn, checkOut]
        );
        assignments = assignRes.rows;
      }
      return {
        bookingRow:     booking,
        bedRow:         bed,
        sourceBeds:     bedsRes.rows,
        assignmentRows: assignments,
      };
    });
    bookingRow     = result.bookingRow;
    bedRow         = result.bedRow;
    sourceBeds     = result.sourceBeds;
    assignmentRows = result.assignmentRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'move preview query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error: 'booking not found',
      preview_only: true,
      would_mutate: false,
    });
  }

  if (!bedRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'target_bed_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error: 'target bed not found',
      preview_only: true,
      would_mutate: false,
    });
  }

  if (targetRoomId && bedRow.room_id !== targetRoomId) {
    appendAuditLog({ ...auditBase, success: false, error: 'target_room_mismatch', elapsed_ms: Date.now() - started });
    return sendJSON(res, 400, {
      success: false,
      error: 'target_room_id does not match the target bed room',
      preview_only: true,
      would_mutate: false,
    });
  }

  if (checkIn !== bookingRow.check_in || checkOut !== bookingRow.check_out) {
    appendAuditLog({ ...auditBase, success: false, error: 'date_change_not_supported_in_phase_10_3', elapsed_ms: Date.now() - started });
    return sendJSON(res, 400, {
      success: false,
      can_move: false,
      error: 'date_change_not_supported_in_phase_10_3',
      message: 'Date changes are not supported in Phase 10.3. Request dates must match the booking stay.',
      preview_only: true,
      would_mutate: false,
    });
  }

  const resolvedPreview = moveResolveSourceBed(sourceBeds, bookingBedId);
  if (resolvedPreview.status === 'requires_selection') {
    const elapsedSel = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_move: false,
      requires_selection: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: elapsedSel,
    });
    return sendJSON(res, 200, {
      success: true,
      can_move: false,
      preview_only: true,
      would_mutate: false,
      requires_selection: true,
      reason: resolvedPreview.reason,
      assignments: resolvedPreview.assignments,
      booking: movePreviewBookingSummary(bookingRow),
      message: resolvedPreview.message,
      elapsed_ms: elapsedSel,
    });
  }
  if (resolvedPreview.status === 'manual_review') {
    const elapsedMr = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_move: false,
      requires_manual_review: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: elapsedMr,
    });
    return sendJSON(res, 200, {
      success: true,
      can_move: false,
      preview_only: true,
      would_mutate: false,
      requires_manual_review: true,
      reason: resolvedPreview.reason,
      booking: movePreviewBookingSummary(bookingRow),
      message: resolvedPreview.message,
      elapsed_ms: elapsedMr,
    });
  }
  if (resolvedPreview.status === 'invalid_id') {
    appendAuditLog({ ...auditBase, success: false, error: resolvedPreview.error, elapsed_ms: Date.now() - started });
    return sendJSON(res, resolvedPreview.httpStatus || 400, {
      success: false,
      error: resolvedPreview.error,
      preview_only: true,
      would_mutate: false,
    });
  }

  const sourceBed = resolvedPreview.sourceBed;
  if (sourceBed.check_in !== checkIn || sourceBed.check_out !== checkOut) {
    const elapsedMis = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_move: false,
      requires_manual_review: true,
      error: 'assignment_date_mismatch',
      elapsed_ms: elapsedMis,
    });
    return sendJSON(res, 200, {
      success: true,
      can_move: false,
      preview_only: true,
      would_mutate: false,
      requires_manual_review: true,
      reason: 'assignment_date_mismatch',
      booking: movePreviewBookingSummary(bookingRow),
      source_assignment: moveWriteAssignmentSummary(sourceBed, null),
      message: 'Assignment dates do not match the booking stay. Manual review required.',
      elapsed_ms: elapsedMis,
    });
  }

  const target = {
    bed_id:    bedRow.bed_id,
    room_id:   bedRow.room_id,
    bed_code:  bedRow.bed_code,
    room_code: bedRow.room_code,
    room_name: bedRow.room_name,
    check_in:  checkIn,
    check_out: checkOut,
    nights,
  };

  if (
    sourceBed.bed_id === bedRow.bed_id &&
    sourceBed.bed_code === bedRow.bed_code
  ) {
    const elapsedIdem = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, can_move: true, idempotent: true, elapsed_ms: elapsedIdem });
    return sendJSON(res, 200, {
      success: true,
      can_move: true,
      idempotent: true,
      preview_only: true,
      would_mutate: false,
      booking: movePreviewBookingSummary(bookingRow),
      source_assignment: moveWriteAssignmentSummary(sourceBed, null),
      target,
      conflicts: [],
      message: 'Move preview passed. Selected assignment is already on the target bed.',
      elapsed_ms: elapsedIdem,
    });
  }

  if (bedRow.active === false || bedRow.sellable === false) {
    appendAuditLog({ ...auditBase, success: false, can_move: false, error: 'target_bed_unavailable', elapsed_ms: Date.now() - started });
    return sendJSON(res, 200, {
      success: true,
      can_move: false,
      preview_only: true,
      would_mutate: false,
      booking: movePreviewBookingSummary(bookingRow),
      source_assignment: moveWriteAssignmentSummary(sourceBed, null),
      target,
      conflicts: [],
      message: 'Target bed is not active or sellable. No changes were made.',
      elapsed_ms: Date.now() - started,
    });
  }

  // Assignment-scoped conflicts (booking_bed_id; not row.booking_id !== sourceBookingId)
  const conflicts = moveWriteBuildConflicts(
    assignmentRows,
    sourceBed.booking_bed_id,
    checkIn,
    checkOut,
    bedRow
  );

  const canMove = conflicts.length === 0;
  const elapsed = Date.now() - started;

  appendAuditLog({
    ...auditBase,
    success: true,
    can_move: canMove,
    conflict_count: conflicts.length,
    booking_bed_id: sourceBed.booking_bed_id,
    elapsed_ms: elapsed,
  });

  return sendJSON(res, 200, {
    success: true,
    can_move: canMove,
    preview_only: true,
    would_mutate: false,
    booking: movePreviewBookingSummary(bookingRow),
    source_assignment: moveWriteAssignmentSummary(sourceBed, null),
    target,
    conflicts,
    message: canMove
      ? 'Move preview passed. No changes were made.'
      : 'Target bed is not available for this date range. No changes were made.',
    elapsed_ms: elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.4b — Booking date-change preview (read-only; no writes)
//
// POST /staff/bookings/date-change-preview
//
// Preview whether an existing single-bed booking can move to new check_in/check_out
// on the same bed (or optional target_bed_id). SELECT-only — no mutation.
// Date-change write deferred to Phase 10.5.
// ─────────────────────────────────────────────────────────────────────────────

function dateChangePreviewBookingSummary(row) {
  return {
    booking_id:     row.booking_id,
    booking_code:   row.booking_code,
    guest_name:     row.guest_name,
    payment_status: row.payment_status,
  };
}

function dateChangePreviewStaySummary(checkIn, checkOut, bedRow, nights, nightsDelta) {
  const stay = {
    check_in:  checkIn,
    check_out: checkOut,
    nights,
    bed_id:    bedRow.bed_id,
    bed_code:  bedRow.bed_code,
    room_code: bedRow.room_code,
  };
  if (nightsDelta != null) stay.nights_delta = nightsDelta;
  return stay;
}

function dateChangePreviewPricingImpact(currentNights, proposedNights) {
  const nightsDelta = proposedNights - currentNights;
  return {
    requires_reprice:  nightsDelta !== 0,
    nights_delta:      nightsDelta,
    payment_mutation:  false,
    stripe_mutation:   false,
    note: 'Preview only. No payment or Stripe changes were made.',
  };
}

function dateChangePreviewBuildConflicts(assignmentRows, sourceBookingId, checkIn, checkOut, bedRow) {
  return assignmentRows
    .filter((row) => row.booking_id !== sourceBookingId)
    .filter(movePreviewIsBlockingAssignment)
    .filter((row) => movePreviewHalfOpenOverlaps(row.check_in, row.check_out, checkIn, checkOut))
    .map((row) => ({
      booking_id:   row.booking_id,
      booking_code: row.booking_code,
      guest_name:   row.guest_name,
      check_in:     row.check_in,
      check_out:    row.check_out,
      bed_id:       bedRow.bed_id,
      bed_code:     row.bed_code || bedRow.bed_code,
    }));
}

async function handleBookingDateChangePreview(req, res, user) {
  const started = Date.now();

  let body = {};
  try {
    const raw = await readBody(req);
    body = JSON.parse(raw || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug   = String(body.client_slug || body.client || DEFAULT_CLIENT).trim();
  const bookingId    = String(body.booking_id   || '').trim();
  const bookingCode  = String(body.booking_code || '').trim();
  const newCheckIn   = String(body.new_check_in  || '').trim();
  const newCheckOut  = String(body.new_check_out || '').trim();
  const targetBedId  = String(body.target_bed_id || '').trim();
  const reason       = String(body.reason || '').trim().slice(0, 500) || null;

  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!clientSlug) return send400(res, 'client_slug is required');
  if (!bookingId && !bookingCode) return send400(res, 'booking_id or booking_code is required');
  if (bookingId && !UUID_VALIDATE_RE.test(bookingId)) return send400(res, 'booking_id must be a valid UUID');
  if (targetBedId && !UUID_VALIDATE_RE.test(targetBedId)) return send400(res, 'target_bed_id must be a valid UUID');
  if (!newCheckIn || !newCheckOut) return send400(res, 'new_check_in and new_check_out are required (YYYY-MM-DD)');
  if (!DATE_RE.test(newCheckIn) || !DATE_RE.test(newCheckOut)) return send400(res, 'new_check_in and new_check_out must be YYYY-MM-DD');
  if (!parseCalendarDate(newCheckIn) || !parseCalendarDate(newCheckOut)) return send400(res, 'new_check_in and new_check_out must be valid dates');
  if (newCheckOut <= newCheckIn) return send400(res, 'new_check_out must be after new_check_in');

  const actorId   = user ? user.staff_user_id : 'dev-date-change-preview-local';
  const actorRole = user ? user.role          : 'operator';

  const auditBase = {
    ts:            new Date().toISOString(),
    intent:        'api:booking_date_change_preview',
    category:      'booking_date_change_preview',
    preview_only:  true,
    would_mutate:  false,
    client_slug:   clientSlug,
    booking_id:    bookingId || null,
    booking_code:  bookingCode || null,
    new_check_in:  newCheckIn,
    new_check_out: newCheckOut,
    target_bed_id: targetBedId || null,
    reason,
    staff_user_id: actorId,
    staff_role:    actorRole,
  };

  let bookingRow, bedRow, sourceBeds, assignmentRows;
  try {
    const result = await withPgClient(async (pg) => {
      const bookingRes = await pg.query(
        bookingId ? MOVE_PREVIEW_BOOKING_BY_ID_SQL : MOVE_PREVIEW_BOOKING_BY_CODE_SQL,
        [clientSlug, bookingId || bookingCode]
      );
      const booking = bookingRes.rows[0] || null;
      if (!booking) {
        return { bookingRow: null, bedRow: null, sourceBeds: [], assignmentRows: [] };
      }
      const bedsRes = await pg.query(MOVE_WRITE_SOURCE_BEDS_SQL, [clientSlug, booking.booking_id]);
      const sourceBedsRows = bedsRes.rows;
      const resolvedBedId = targetBedId || (sourceBedsRows[0] && sourceBedsRows[0].bed_id) || '';
      let bed = null;
      let assignments = [];
      if (resolvedBedId) {
        const bedRes = await pg.query(MOVE_PREVIEW_BED_BY_ID_SQL, [clientSlug, resolvedBedId]);
        bed = bedRes.rows[0] || null;
        if (bed && bed.bed_code) {
          const assignRes = await pg.query(
            MOVE_PREVIEW_TARGET_ASSIGNMENTS_SQL,
            [clientSlug, bed.bed_code, newCheckIn, newCheckOut]
          );
          assignments = assignRes.rows;
        }
      }
      return {
        bookingRow:     booking,
        bedRow:         bed,
        sourceBeds:     sourceBedsRows,
        assignmentRows: assignments,
      };
    });
    bookingRow     = result.bookingRow;
    bedRow         = result.bedRow;
    sourceBeds     = result.sourceBeds;
    assignmentRows = result.assignmentRows;
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'date-change preview query failed', detail: err.message });
  }

  if (!bookingRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'booking_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error: 'booking not found',
      preview_only: true,
      would_mutate: false,
    });
  }

  if (sourceBeds.length !== 1) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      can_change_dates: false,
      requires_manual_review: true,
      source_bed_count: sourceBeds.length,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      can_change_dates: false,
      preview_only: true,
      would_mutate: false,
      requires_manual_review: true,
      reason: 'single_bed_booking_required',
      booking: dateChangePreviewBookingSummary(bookingRow),
      message: 'This booking has multiple or no active bed assignments and requires manual review.',
      elapsed_ms: elapsed,
    });
  }

  const sourceBed = sourceBeds[0];
  const resolvedTargetBedId = targetBedId || sourceBed.bed_id;

  if (!bedRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'target_bed_not_found', elapsed_ms: Date.now() - started });
    return sendJSON(res, 404, {
      success: false,
      error: 'target bed not found',
      preview_only: true,
      would_mutate: false,
    });
  }

  if (bedRow.bed_id !== resolvedTargetBedId) {
    appendAuditLog({ ...auditBase, success: false, error: 'target_bed_mismatch', elapsed_ms: Date.now() - started });
    return sendJSON(res, 400, {
      success: false,
      error: 'target_bed_id does not match resolved bed',
      preview_only: true,
      would_mutate: false,
    });
  }

  const currentNights  = movePreviewNights(bookingRow.check_in, bookingRow.check_out);
  const proposedNights = movePreviewNights(newCheckIn, newCheckOut);
  const pricingImpact  = dateChangePreviewPricingImpact(currentNights, proposedNights);
  const currentStay    = dateChangePreviewStaySummary(
    bookingRow.check_in,
    bookingRow.check_out,
    { bed_id: sourceBed.bed_id, bed_code: sourceBed.bed_code, room_code: sourceBed.room_code },
    currentNights
  );
  const proposedStay   = dateChangePreviewStaySummary(
    newCheckIn,
    newCheckOut,
    bedRow,
    proposedNights,
    pricingImpact.nights_delta
  );

  if (bedRow.active === false || bedRow.sellable === false) {
    const elapsed = Date.now() - started;
    appendAuditLog({ ...auditBase, success: true, can_change_dates: false, error: 'target_bed_unavailable', elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      can_change_dates: false,
      preview_only: true,
      would_mutate: false,
      requires_manual_review: false,
      booking: dateChangePreviewBookingSummary(bookingRow),
      current: currentStay,
      proposed: proposedStay,
      conflicts: [],
      pricing_impact: pricingImpact,
      message: 'Current bed is not active or sellable for the proposed dates. No changes were made.',
      elapsed_ms: elapsed,
    });
  }

  const sourceBookingId = bookingRow.booking_id;
  const conflicts = dateChangePreviewBuildConflicts(
    assignmentRows,
    sourceBookingId,
    newCheckIn,
    newCheckOut,
    bedRow
  );
  const canChangeDates = conflicts.length === 0;
  const elapsed = Date.now() - started;

  appendAuditLog({
    ...auditBase,
    success: true,
    can_change_dates: canChangeDates,
    conflict_count: conflicts.length,
    elapsed_ms: elapsed,
  });

  return sendJSON(res, 200, {
    success: true,
    can_change_dates: canChangeDates,
    preview_only: true,
    would_mutate: false,
    requires_manual_review: false,
    booking: dateChangePreviewBookingSummary(bookingRow),
    current: currentStay,
    proposed: proposedStay,
    conflicts,
    pricing_impact: pricingImpact,
    message: canChangeDates
      ? 'Date-change preview passed. No changes were made.'
      : 'Current bed is not available for the proposed dates. No changes were made.',
    elapsed_ms: elapsed,
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 10.4f — Booking edit preview (calculate-only; no writes)
//
// POST /staff/bookings/edit-preview
//
// Broad field-level edit preview: contact, dates, package, guest decrease.
// SELECT/calculate-only — no UPDATE/INSERT/DELETE. Write deferred to Phase 10.5.
// ─────────────────────────────────────────────────────────────────────────────

const EDIT_PREVIEW_VALID_TYPES = Object.freeze(['contact', 'dates', 'package', 'guests']);
const EDIT_WRITE_SUPPORTED_TYPES = Object.freeze(['contact', 'package', 'dates', 'guests', 'private_room']);
const EDIT_PREVIEW_ACCOMM_LINE_CODES = Object.freeze({
  package: true, package_proration: true, room_supplement: true,
  accommodation_only: true, manual_accommodation: true,
  // Per-guest package lines (multi-guest bookings with guest_packages). Without
  // these the quote_snapshot accommodation lines aren't recognized, so the
  // running invoice falls back to "total - services" and added services net out.
  guest_package: true, guest_package_proration: true, guest_accommodation_only: true,
});
const EDIT_PREVIEW_PACKAGE_FALLBACK = Object.freeze(['malibu', 'uluwatu', 'waimea']);

const EDIT_PREVIEW_BOOKING_BY_ID_SQL = `
SELECT
  b.id::text                AS booking_id,
  b.booking_code,
  b.guest_name,
  b.phone,
  b.email,
  b.guest_count,
  b.package_code,
  b.check_in::text          AS check_in,
  b.check_out::text         AS check_out,
  b.status::text            AS status,
  b.payment_status::text    AS payment_status,
  b.total_amount_cents,
  b.amount_paid_cents,
  b.balance_due_cents,
  b.deposit_required_cents,
  b.requested_room_type,
  b.room_preference,
  b.primary_room_code,
  b.metadata
FROM bookings b
INNER JOIN clients c ON c.id = b.client_id
WHERE c.slug = $1
  AND b.id::text = $2
LIMIT 1
`;

/* Phase 10.6b — payment ledger rows include metadata for method/source display */
const BOOKING_PAYMENTS_LEDGER_SQL = `
SELECT
  p.id::text                    AS payment_id,
  p.status::text                AS payment_status,
  p.payment_kind::text          AS payment_kind,
  p.currency,
  p.amount_due_cents,
  p.amount_paid_cents,
  p.paid_at,
  p.checkout_url,
  p.stripe_checkout_session_id,
  p.stripe_payment_intent_id,
  p.metadata,
  p.created_at,
  p.booking_guest_id::text      AS booking_guest_id,
  bg.deposit_amount_cents       AS guest_deposit_amount_cents,
  bg.metadata                   AS guest_metadata
FROM payments p
INNER JOIN bookings b ON b.id = p.booking_id
INNER JOIN clients c ON c.id = b.client_id
LEFT JOIN booking_guests bg ON bg.id = p.booking_guest_id
WHERE c.slug = $1
  AND b.booking_code = $2
ORDER BY p.created_at DESC
`;

function paymentLedgerIsPaidStatus(status) {
  return String(status || '').toLowerCase() === 'paid';
}

function paymentLedgerPaidTotalCents(rows) {
  return (rows || []).reduce((sum, pr) => {
    if (!paymentLedgerIsPaidStatus(pr.payment_status)) return sum;
    return sum + Number(pr.amount_paid_cents || 0);
  }, 0);
}

/* Phase 10.6g.2 — invoice + ledger payment truth (calendar, drawer, stale links) */
function bookingLedgerParseMetadata(raw) {
  if (raw && typeof raw === 'object') return raw;
  if (!raw) return {};
  try { return JSON.parse(raw); } catch (_) { return {}; }
}

function bookingLedgerAccommodationCents(bookingRow, svcDueCents, quoteSnap) {
  const svcSum = Number(svcDueCents || 0);
  if (quoteSnap && Array.isArray(quoteSnap.line_items)) {
    let sum = 0;
    let any = false;
    for (const li of quoteSnap.line_items) {
      if (li.code && EDIT_PREVIEW_ACCOMM_LINE_CODES[li.code] && li.total_cents != null) {
        sum += Number(li.total_cents);
        any = true;
      }
    }
    if (any) return sum;
  }
  if (bookingRow && bookingRow.total_amount_cents != null) {
    const total = Number(bookingRow.total_amount_cents);
    const derived = total - svcSum;
    return derived >= 0 ? derived : total;
  }
  return null;
}

function bookingLedgerInvoicePaidBalance(bookingRow, svcDueCents, ledgerPaidCents, transferDueCents) {
  const bk = bookingRow || {};
  const md = bookingLedgerParseMetadata(bk.metadata);
  const quoteSnap = md.quote_snapshot || null;
  const svcSum = Number(svcDueCents || 0);
  const transferSum = Number(transferDueCents || 0);
  const accCents = bookingLedgerAccommodationCents(bk, svcSum, quoteSnap);
  const invoiceTotal = accCents != null ? accCents + svcSum + transferSum : null;
  const paidTotal = ledgerPaidCents != null ? Number(ledgerPaidCents) : 0;
  const depositRequired = bk.deposit_required_cents != null ? Number(bk.deposit_required_cents) : 0;
  let balanceDue = null;
  let needsRefund = false;
  if (invoiceTotal != null) {
    if (invoiceTotal > paidTotal) balanceDue = invoiceTotal - paidTotal;
    else if (invoiceTotal < paidTotal) { needsRefund = true; balanceDue = 0; }
    else balanceDue = 0;
  }
  return {
    invoice_total_cents: invoiceTotal,
    paid_total_cents: paidTotal,
    balance_due_cents: balanceDue,
    deposit_required_cents: depositRequired,
    needs_refund: needsRefund,
  };
}

function paymentLedgerNormalizeCtx(ctxOrBalance, bookingRow) {
  if (ctxOrBalance != null && typeof ctxOrBalance === 'object' && !Array.isArray(ctxOrBalance)) {
    return ctxOrBalance;
  }
  const bk = bookingRow || {};
  return {
    balance_due_cents: ctxOrBalance,
    deposit_required_cents: bk.deposit_required_cents != null ? Number(bk.deposit_required_cents) : null,
    invoice_total_cents: bk.invoice_total_cents != null ? Number(bk.invoice_total_cents) : null,
  };
}

/* paymentLinkIntendedAmountCents — scripts/lib/payment-ledger-stale-links.js */

function paymentLedgerHasActiveValidLink(rows, ledgerCtx) {
  for (const pr of rows || []) {
    if (paymentLedgerIsActiveUnpaidLinkRow(pr) && !paymentLedgerIsStaleUnpaidLinkRow(pr, ledgerCtx)) {
      return true;
    }
  }
  return false;
}

function bookingCalendarPaymentDisplayState(ledgerTotals, hasActiveLink) {
  const invoice = ledgerTotals.invoice_total_cents;
  const paid = ledgerTotals.paid_total_cents;
  const balance = ledgerTotals.balance_due_cents;
  const depositReq = Number(ledgerTotals.deposit_required_cents || 0);
  const link = !!hasActiveLink;

  if (invoice != null && paid != null && invoice > 0 && paid > invoice) {
    return {
      primary: 'refund_review',
      amount_cents: paid - invoice,
      show_deposit_paid: false,
      has_active_payment_link: link,
    };
  }
  if (balance != null && balance > 0) {
    const showDepositPaid = depositReq > 0 && paid >= depositReq;
    return {
      primary: 'balance_due',
      amount_cents: balance,
      show_deposit_paid: showDepositPaid,
      has_active_payment_link: link,
    };
  }
  if (balance === 0 && invoice != null && invoice > 0) {
    return {
      primary: 'paid',
      amount_cents: 0,
      show_deposit_paid: false,
      has_active_payment_link: link,
    };
  }
  if (link) {
    return {
      primary: 'payment_link_created',
      amount_cents: 0,
      show_deposit_paid: false,
      has_active_payment_link: true,
    };
  }
  return null;
}

const PAYMENT_LEDGER_CANCELLABLE_LINK_STATUSES = new Set(['checkout_created', 'draft', 'pending']);

function paymentLedgerParseMetadata(raw) {
  if (raw && typeof raw === 'object') return raw;
  if (!raw) return {};
  try { return JSON.parse(raw); } catch (_) { return {}; }
}

function paymentLedgerIsCancelledLinkStatus(status) {
  const s = String(status || '').toLowerCase();
  return s === 'cancelled' || s === 'canceled' || s === 'expired' || s === 'failed';
}

function paymentLedgerRowHasLinkUrl(pr) {
  if (!pr) return false;
  if (pr.checkout_url) return true;
  const md = paymentLedgerParseMetadata(pr.metadata);
  return !!(md.payment_link_url || md.checkout_url);
}

function paymentLedgerCanCancelLinkRow(pr) {
  if (!pr) return false;
  const st = String(pr.payment_status || '').toLowerCase();
  if (paymentLedgerIsCancelledLinkStatus(st)) return false;
  if (!PAYMENT_LEDGER_CANCELLABLE_LINK_STATUSES.has(st)) return false;
  if (Number(pr.amount_paid_cents || 0) > 0) return false;
  if (!paymentLedgerRowHasLinkUrl(pr)) return false;
  return true;
}

function paymentLedgerIsActiveUnpaidLinkRow(pr) {
  if (!pr) return false;
  const st = String(pr.payment_status || '').toLowerCase();
  if (paymentLedgerIsCancelledLinkStatus(st)) return false;
  if (!PAYMENT_LEDGER_CANCELLABLE_LINK_STATUSES.has(st)) return false;
  if (Number(pr.amount_paid_cents || 0) > 0) return false;
  if (st === 'draft' && !paymentLedgerRowHasLinkUrl(pr) && !pr.checkout_url) return false;
  return !!(pr.checkout_url || paymentLedgerRowHasLinkUrl(pr));
}

function paymentLedgerIsStaleUnpaidLinkRow(pr, ledgerCtxOrBalance, bookingRow) {
  const ledgerCtx = paymentLedgerNormalizeCtx(ledgerCtxOrBalance, bookingRow);
  return paymentLedgerIsStaleUnpaidLinkRowCore(pr, paymentLedgerIsActiveUnpaidLinkRow, ledgerCtx);
}

function ledgerActivePaymentLinkRow(rows, ledgerCtxOrBalance, bookingRow) {
  const ledgerCtx = paymentLedgerNormalizeCtx(ledgerCtxOrBalance, bookingRow);
  const balanceDue = ledgerCtx.balance_due_cents;
  if (balanceDue == null || balanceDue <= 0) return null;
  for (const pr of rows || []) {
    const st = String(pr.payment_status || '').toLowerCase();
    if (paymentLedgerIsCancelledLinkStatus(st)) continue;
    if (paymentLedgerIsStaleUnpaidLinkRow(pr, ledgerCtx)) continue;
    const intended = paymentLinkIntendedAmountCents(pr, ledgerCtx);
    if ((st === 'checkout_created' || st === 'draft' || st === 'pending')
        && pr.checkout_url
        && intended != null
        && Number(pr.amount_due_cents) === Number(intended)
        && Number(pr.amount_paid_cents || 0) === 0) {
      return pr;
    }
  }
  return null;
}

function bookingLedgerBalanceFromRows(bookingRow, svcRows, paymentRows, transferRows) {
  const svcDue = editPreviewSvcSum(svcRows);
  const paidCents = paymentLedgerPaidTotalCents(paymentRows);
  const transferDue = sumActiveTransferChargesCents(transferRows);
  const totals = bookingLedgerInvoicePaidBalance(bookingRow, svcDue, paidCents, transferDue);
  const line_items = editPreviewBuildLineItems(
    bookingLedgerAccommodationCents(
      bookingRow,
      svcDue,
      (bookingLedgerParseMetadata(bookingRow.metadata).quote_snapshot) || null,
    ),
    svcRows,
    null,
  );
  return {
    line_items,
    total_amount_cents: totals.invoice_total_cents,
    paid_amount_cents: totals.paid_total_cents,
    balance_due_cents: totals.balance_due_cents,
    needs_refund: totals.needs_refund,
    invoice_total_cents: totals.invoice_total_cents,
    paid_total_cents: totals.paid_total_cents,
    deposit_required_cents: totals.deposit_required_cents,
  };
}

