function editPreviewKnownPackageCodes() {
  try {
    const cfgPath = path.join(__dirname, '..', 'config', 'clients', 'wolfhouse-somo.pricing.json');
    const cfg = JSON.parse(fs.readFileSync(cfgPath, 'utf8'));
    return (cfg.packages || []).map((p) => String(p.code).toLowerCase());
  } catch (_) {
    return [...EDIT_PREVIEW_PACKAGE_FALLBACK];
  }
}

function editPreviewIsValidPackage(code, currentCode) {
  const c = String(code || '').trim().toLowerCase();
  if (!c) return false;
  if (c === 'no_package' || c === 'package_none' || c === 'accommodation_only') return true;
  const known = editPreviewKnownPackageCodes();
  if (known.includes(c)) return true;
  if (currentCode && c === String(currentCode).trim().toLowerCase()) return true;
  return false;
}

/** Maps UI package selector values to DB storage (null = no package). */
function editPreviewPackageStorageCode(raw) {
  const c = String(raw || '').trim().toLowerCase();
  if (!c || c === 'no_package' || c === 'package_none') return null;
  return c;
}

/** Package code for calculateWolfhouseQuote — no package uses Malibu-ref accommodation pricing. */
function editPreviewQuotePackageCode(raw) {
  const c = String(raw || '').trim().toLowerCase();
  if (!c || c === 'no_package' || c === 'package_none') return 'no_package';
  return c;
}

function editPreviewLightEmailOk(email) {
  if (email == null || String(email).trim() === '') return true;
  const e = String(email).trim();
  if (e.length > 254) return false;
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
}

function editPreviewLightNameOk(name) {
  if (name == null) return true;
  return String(name).trim().length <= 200;
}

function editPreviewLightPhoneOk(phone) {
  if (phone == null || String(phone).trim() === '') return true;
  return String(phone).trim().length <= 40;
}

