// Route: POST /staff/bot/guest-intake-dry-run  (Stage 27c/27g/27i/27k — read-only)
//
// Guest message → Stage 27b lane router → optional Stage 27f availability → optional Stage 27h quote
// → optional Stage 27j payment choice (when guest_context carries prior quote).
// No writes, WhatsApp, Meta, n8n, Stripe, or payment links.
async function handleBotGuestIntakeDryRun(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const messageText = body.message_text != null ? String(body.message_text).trim() : '';
  if (!messageText) {
    return sendJSON(res, 400, {
      success:            false,
      dry_run:            true,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      error:              'message_text is required',
    });
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId          = user ? user.staff_user_id : 'dev-bot-guest-intake-dry-run-local';

  try {
    const input = {
      message_text:  messageText,
      language_hint: body.language_hint,
      guest_context: body.guest_context,
    };
    const context = {
      reference_date: body.reference_date || undefined,
      guest_phone:    body.guest_phone
        || (body.guest_context && body.guest_context.guest_phone)
        || undefined,
    };

    const result = runLunaGuestMessageRouterDryRun(input, context);

    let availability;
    if (shouldAttemptGuestAvailability(result)) {
      try {
        availability = await withPgClient((pg) => runGuestAvailabilityDryRun(result, {
          pg,
          client_slug: body.client_slug || DEFAULT_CLIENT,
          room_type: body.room_type,
        }));
      } catch (_) {
        availability = {
          success: true,
          dry_run: true,
          preview_only: true,
          no_write_performed: true,
          live_send_blocked: true,
          sends_whatsapp: false,
          availability_check_attempted: true,
          availability_status: 'error',
          availability_result_summary: 'Availability check failed.',
          availability_handoff_required: true,
          availability_handoff_reasons: ['availability_check_error'],
        };
      }
    } else {
      availability = buildGuestAvailabilitySkippedResponse(result);
    }

    const quoteContext = {
      client_slug: body.client_slug || DEFAULT_CLIENT,
      room_type: body.room_type,
    };
    let quote;
    if (shouldAttemptGuestQuoteProposal(result, availability)) {
      try {
        quote = runGuestQuoteProposalDryRun(result, availability, quoteContext);
      } catch (_) {
        quote = {
          success: true,
          dry_run: true,
          preview_only: true,
          no_write_performed: true,
          live_send_blocked: true,
          sends_whatsapp: false,
          quote_proposal_attempted: true,
          quote_status: 'error',
          quote_result_summary: 'Quote calculation failed.',
          quote_total_cents: null,
          deposit_options: null,
          payment_choice_needed: false,
          quote_handoff_required: true,
          quote_handoff_reasons: ['quote_calculation_error'],
          proposed_luna_reply: availability.proposed_luna_reply || result.proposed_luna_reply,
        };
      }
    } else {
      quote = buildGuestQuoteSkippedResponse(result, availability);
    }

    let payment_choice;
    if (shouldAttemptGuestPaymentChoiceWire(body.guest_context)) {
      const paymentChoiceContext = buildPaymentChoiceWireContext(
        body.guest_context,
        result,
        availability,
        quote,
      );
      payment_choice = runGuestPaymentChoiceDryRun(
        { message_text: messageText, language_hint: body.language_hint },
        paymentChoiceContext,
      );
    } else {
      payment_choice = buildGuestPaymentChoiceWireSkippedResponse(body.guest_context);
    }

    const elapsed = Date.now() - started;

    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_guest_intake_dry_run',
      category:           'bot_guest_intake_dry_run',
      dry_run:            true,
      preview_only:       true,
      no_write_performed: true,
      creates_booking:    false,
      creates_payment:    false,
      creates_stripe_link: false,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      calls_n8n:          false,
      success:            result.success === true,
      message_lane:       result.message_lane,
      intake_state:       result.intake_state,
      safe_handoff_required: result.safe_handoff_required,
      availability_check_attempted: availability.availability_check_attempted === true,
      availability_status: availability.availability_status || null,
      quote_proposal_attempted: quote.quote_proposal_attempted === true,
      quote_status: quote.quote_status || null,
      payment_choice_capture_attempted: payment_choice.payment_choice_capture_attempted === true,
      payment_choice_ready: payment_choice.payment_choice_ready === true,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });

    if (result.success === false) {
      return sendJSON(res, 400, {
        success:           false,
        dry_run:           true,
        sends_whatsapp:    false,
        live_send_blocked: true,
        error:             result.error || 'guest intake dry-run failed',
        auth_mode:         resolvedAuthMode,
        elapsed_ms:        elapsed,
      });
    }

    return sendJSON(res, 200, {
      success:           true,
      dry_run:           true,
      sends_whatsapp:    false,
      live_send_blocked: true,
      no_write_performed: true,
      result,
      availability,
      quote,
      payment_choice,
      auth_mode:         resolvedAuthMode,
      elapsed_ms:        elapsed,
    });
  } catch (_) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_guest_intake_dry_run',
      category:           'bot_guest_intake_dry_run',
      dry_run:            true,
      preview_only:       true,
      no_write_performed: true,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      success:            false,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });
    return sendJSON(res, 500, {
      success:           false,
      dry_run:           true,
      sends_whatsapp:    false,
      live_send_blocked: true,
      error:             'guest intake dry-run failed',
      auth_mode:         resolvedAuthMode,
      elapsed_ms:        elapsed,
    });
  }
}

function collectGuestAutomationReviewHandoffReasons(orchOut) {
  const reasons = [];
  const push = (arr) => {
    if (!Array.isArray(arr)) return;
    for (const r of arr) {
      if (r != null && String(r).trim()) reasons.push(String(r).trim());
    }
  };
  if (orchOut && orchOut.automation_gate) push(orchOut.automation_gate.gate_reasons);
  if (orchOut && orchOut.result) {
    push(orchOut.result.handoff_reasons);
    if (orchOut.result.safe_handoff_required) reasons.push('staff_handoff_required');
  }
  if (orchOut && orchOut.availability) push(orchOut.availability.availability_handoff_reasons);
  if (orchOut && orchOut.quote) push(orchOut.quote.quote_handoff_reasons);
  if (orchOut && orchOut.payment_choice) push(orchOut.payment_choice.payment_choice_reasons);
  if (orchOut && orchOut.hold_payment_draft_plan) {
    push(orchOut.hold_payment_draft_plan.plan_handoff_reasons);
  }
  return [...new Set(reasons)];
}

// Route: POST /staff/bot/guest-automation-review-dry-run  (Stage 27v — staff review)
//
// Staff-only preview of Stage 27u orchestrator: gate, chain state, proposed reply.
// No writes, WhatsApp, Meta, n8n, Stripe, or public inbound wiring.
async function handleBotGuestAutomationReviewDryRun(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const clientSlug = body.client_slug != null ? String(body.client_slug).trim() : '';
  const channel = body.channel != null ? String(body.channel).trim() : '';
  const messageText = body.message_text != null ? String(body.message_text).trim() : '';

  const missing = [];
  if (!clientSlug) missing.push('client_slug');
  if (!channel) missing.push('channel');
  if (!messageText) missing.push('message_text');
  if (missing.length > 0) {
    return sendJSON(res, 400, {
      success:           false,
      dry_run:           true,
      sends_whatsapp:    false,
      live_send_blocked: true,
      error:             `${missing.join(', ')} ${missing.length === 1 ? 'is' : 'are'} required`,
    });
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId          = user ? user.staff_user_id : 'dev-bot-guest-automation-review-local';

  try {
    const input = {
      client_slug:             clientSlug,
      channel,
      message_text:            messageText,
      guest_phone:             body.guest_phone,
      conversation_id:         body.conversation_id,
      language_hint:           body.language_hint,
      guest_context:           body.guest_context,
      reference_date:          body.reference_date,
      automation_gate_context: body.automation_gate_context,
      dry_run:                 true,
    };
    const context = {
      reference_date: body.reference_date || undefined,
      guest_phone:    body.guest_phone
        || (body.guest_context && body.guest_context.guest_phone)
        || undefined,
      dry_run:        true,
    };

    const orchOut = await withPgClient((pg) => runGuestAutomationOrchestratorDryRun(input, {
      ...context,
      pg,
    }));

    const elapsed = Date.now() - started;

    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_guest_automation_review_dry_run',
      category:           'bot_guest_automation_review_dry_run',
      dry_run:            true,
      preview_only:       true,
      no_write_performed: true,
      creates_booking:    false,
      creates_payment:    false,
      creates_stripe_link: false,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      calls_n8n:          false,
      success:            orchOut.success === true,
      gate_status:        orchOut.automation_gate && orchOut.automation_gate.gate_status,
      proposed_next_action: orchOut.proposed_next_action || null,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });

    return sendJSON(res, 200, {
      success:           true,
      dry_run:           true,
      sends_whatsapp:    false,
      live_send_blocked: true,
      no_write_performed: true,
      review: {
        automation_gate:         orchOut.automation_gate,
        proposed_next_action:    orchOut.proposed_next_action,
        proposed_luna_reply:     orchOut.proposed_luna_reply,
        result:                  orchOut.result,
        availability:            orchOut.availability,
        quote:                   orchOut.quote,
        payment_choice:          orchOut.payment_choice,
        hold_payment_draft_plan: orchOut.hold_payment_draft_plan,
        handoff_reasons:         collectGuestAutomationReviewHandoffReasons(orchOut),
      },
      auth_mode:         resolvedAuthMode,
      elapsed_ms:        elapsed,
    });
  } catch (err) {
    const elapsed = Date.now() - started;
    const corr = extractReviewDryRunCorrelation(req, body);
    logReviewDryRunError({
      endpoint: 'guest-automation-review-dry-run',
      ...corr,
      client_slug: clientSlug,
      channel,
      guest_phone: body.guest_phone,
      message_length: messageText.length,
      error: err,
      elapsed_ms: elapsed,
    });
    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_guest_automation_review_dry_run',
      category:           'bot_guest_automation_review_dry_run',
      dry_run:            true,
      preview_only:       true,
      no_write_performed: true,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      success:            false,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });
    return sendJSON(res, 500, buildSafeReviewDryRun500Body({
      error: 'guest automation review dry-run failed',
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    }));
  }
}

