// Route: POST /staff/bot/open-demo-whatsapp-inbound-dry-run  (Stage 27demo-b/c/d)
//
// n8n open demo WhatsApp pipe → 27x.1 inbound review → inbox/draft persistence.
// Optional send_live_reply_confirmed (27demo-c) or create_demo_hold_draft_confirmed (27demo-d).
// No Stripe link, payment link send, or confirmation send.
async function handleBotOpenDemoWhatsAppInboundDryRun(req, res, user, authMode) {
  const started = Date.now();

  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId          = user ? user.staff_user_id : 'dev-bot-open-demo-whatsapp-local';

  const gate = evaluateOpenDemoWhatsAppGate(body);
  if (!gate.ok) {
    const elapsed = Date.now() - started;
    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_open_demo_whatsapp_inbound_dry_run',
      category:           'open_demo_whatsapp_inbound',
      dry_run:            true,
      preview_only:       true,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      success:            false,
      demo_gate_code:     gate.code,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });
    return sendJSON(res, gate.status || 403, {
      ...buildOpenDemoBlockedResponse(gate),
      auth_mode:  resolvedAuthMode,
      elapsed_ms: elapsed,
    });
  }

  const validation = validateOpenDemoInboundBody(body);
  if (!validation.ok) {
    const elapsed = Date.now() - started;
    return sendJSON(res, 400, {
      success:           false,
      dry_run:           true,
      open_demo:         true,
      sends_whatsapp:    false,
      live_send_blocked: true,
      error:             `${validation.missing.join(', ')} ${validation.missing.length === 1 ? 'is' : 'are'} required`,
      auth_mode:         resolvedAuthMode,
      elapsed_ms:        elapsed,
    });
  }

  const inboundBody = validation.normalized;
  const sendLiveReplyConfirmed = wantsSendLiveReplyConfirmed(body);
  const createHoldDraftConfirmed = wantsCreateDemoHoldDraftConfirmed(body);
  const assignDemoBedConfirmed = wantsAssignDemoBedConfirmed(body);
  const createStripeTestLinkConfirmed = wantsCreateStripeTestLinkConfirmed(body);
  const sendPaymentLinkWhatsAppConfirmed = wantsSendPaymentLinkWhatsAppConfirmed(body);
  const hostHeader = String(req.headers.host || '');

  try {
    const outcome = await withPgClient((pg) => executeOpenDemoWhatsAppInbound(pg, body, process.env, {
      hostHeader,
      actorId,
    }));
    const elapsed = Date.now() - started;
    const reviewOutcome = outcome.reviewOutcome;

    if (!reviewOutcome.ok) {
      appendAuditLog({
        ts:                 new Date().toISOString(),
        intent:             'api:bot_open_demo_whatsapp_inbound_dry_run',
        category:           'open_demo_whatsapp_inbound',
        dry_run:            true,
        preview_only:       true,
        sends_whatsapp:     false,
        live_send_blocked:  true,
        success:            false,
        staff_user_id:      actorId,
        auth_mode:          resolvedAuthMode,
        elapsed_ms:         elapsed,
      });
      return sendJSON(res, reviewOutcome.status || 400, {
        success:           false,
        dry_run:           true,
        open_demo:         true,
        sends_whatsapp:    false,
        live_send_blocked: true,
        error:             reviewOutcome.error || 'open demo inbound review failed',
        auth_mode:         resolvedAuthMode,
        elapsed_ms:        elapsed,
      });
    }

    const liveReply = outcome.liveReply;
    const bookingWrite = outcome.bookingWrite;
    const bedAssignment = outcome.bedAssignment;
    const stripeLink = outcome.stripeLink;
    const paymentLinkSend = outcome.paymentLinkSend;
    const paymentLinkSent = paymentLinkSend && paymentLinkSend.payment_link_sent === true;
    const sent = (liveReply && liveReply.whatsapp_sent === true) || paymentLinkSent === true;
    const writeCreated = bookingWrite
      && (bookingWrite.write_status === 'created' || bookingWrite.write_status === 'reused_existing');
    const bedAssigned = bedAssignment
      && (bedAssignment.assignment_write_status === 'created'
        || bedAssignment.assignment_write_status === 'reused_existing');
    const stripeLinked = stripeLink
      && (stripeLink.stripe_link_created === true || stripeLink.stripe_link_reused === true);

    const responseBody = {
      ...reviewOutcome.body,
      open_demo:         true,
      demo_gate:         'open_demo_whatsapp_enabled',
      phone_number_id:   inboundBody.phone_number_id || null,
      contact_name:      inboundBody.contact_name || null,
      sends_whatsapp:    sent,
      live_send_blocked: !sent,
      whatsapp_sent:     sent === true,
      send_live_reply_confirmed: sendLiveReplyConfirmed,
      create_demo_hold_draft_confirmed: createHoldDraftConfirmed,
      assign_demo_bed_confirmed: assignDemoBedConfirmed,
      create_stripe_test_link_confirmed: createStripeTestLinkConfirmed,
      send_payment_link_whatsapp_confirmed: sendPaymentLinkWhatsAppConfirmed,
      auth_mode:         resolvedAuthMode,
      elapsed_ms:        elapsed,
    };

    if (outcome.typingIndicator) {
      responseBody.typing_indicator = outcome.typingIndicator;
      responseBody.typing_indicator_sent = outcome.typingIndicator.typing_indicator_sent === true;
    }

    if (liveReply) {
      Object.assign(responseBody, liveReply);
    } else if (!writeCreated && !bedAssigned && !stripeLinked && !paymentLinkSent) {
      responseBody.sends_whatsapp = false;
      responseBody.live_send_blocked = true;
      responseBody.whatsapp_sent = false;
    }

    if (bookingWrite) {
      Object.assign(responseBody, bookingWrite);
    }

    if (bedAssignment) {
      Object.assign(responseBody, bedAssignment);
    }

    if (stripeLink) {
      Object.assign(responseBody, stripeLink);
    }

    if (paymentLinkSend) {
      Object.assign(responseBody, paymentLinkSend);
    }

    if (outcome.serviceAttach) responseBody.serviceAttach = outcome.serviceAttach;
    if (outcome.serviceStripeLink) responseBody.serviceStripeLink = outcome.serviceStripeLink;
    if (outcome.transferTimesUpdate) responseBody.transferTimesUpdate = outcome.transferTimesUpdate;
    if (outcome.serviceSchedule) responseBody.serviceSchedule = outcome.serviceSchedule;
    if (outcome.lunaNotes) responseBody.lunaNotes = outcome.lunaNotes;

    if (paymentLinkSent) {
      responseBody.sends_whatsapp = true;
      responseBody.whatsapp_sent = true;
      responseBody.live_send_blocked = false;
    }

    let auditIntent = 'api:bot_open_demo_whatsapp_inbound_dry_run';
    if (paymentLinkSent) auditIntent = 'api:bot_open_demo_whatsapp_payment_link_send';
    else if (sent) auditIntent = 'api:bot_open_demo_whatsapp_inbound_live_reply';
    else if (stripeLinked) auditIntent = 'api:bot_open_demo_whatsapp_stripe_test_link';
    else if (bedAssigned) auditIntent = 'api:bot_open_demo_whatsapp_bed_assignment';
    else if (writeCreated) auditIntent = 'api:bot_open_demo_whatsapp_booking_write';

    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             auditIntent,
      category:           'open_demo_whatsapp_inbound',
      dry_run:            !sent && !writeCreated && !bedAssigned && !stripeLinked,
      preview_only:       !sent && !writeCreated && !bedAssigned && !stripeLinked,
      sends_whatsapp:     sent,
      live_send_blocked:  !sent,
      creates_booking:    writeCreated,
      creates_payment:    writeCreated,
      creates_stripe_link: stripeLinked,
      review_persistence_performed: responseBody.review_persistence_performed === true,
      idempotent_replay:  responseBody.idempotent_replay === true,
      success:            responseBody.success === true,
      proposed_next_action: responseBody.review && responseBody.review.proposed_next_action,
      write_status:       bookingWrite && bookingWrite.write_status,
      booking_code:       (bookingWrite && bookingWrite.booking_code)
        || (stripeLink && stripeLink.booking_code),
      payment_draft_id:   (bookingWrite && bookingWrite.payment_draft_id)
        || (stripeLink && stripeLink.payment_draft_id),
      assignment_write_status: bedAssignment && bedAssignment.assignment_write_status,
      stripe_checkout_url: stripeLink && stripeLink.stripe_checkout_url,
      payment_link_sent:  paymentLinkSent,
      whatsapp_message_id: (liveReply && liveReply.whatsapp_message_id)
        || (paymentLinkSend && paymentLinkSend.whatsapp_message_id),
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });

    return sendJSON(res, reviewOutcome.status || 200, responseBody);
  } catch (err) {
    const elapsed = Date.now() - started;
    const corr = extractReviewDryRunCorrelation(req, body);
    logReviewDryRunError({
      endpoint: 'open-demo-whatsapp-inbound-dry-run',
      ...corr,
      client_slug: inboundBody.client_slug,
      channel: inboundBody.channel,
      guest_phone: inboundBody.guest_phone,
      message_length: inboundBody.message_text.length,
      error: err,
      elapsed_ms: elapsed,
    });
    appendAuditLog({
      ts:                 new Date().toISOString(),
      intent:             'api:bot_open_demo_whatsapp_inbound_dry_run',
      category:           'open_demo_whatsapp_inbound',
      dry_run:            true,
      preview_only:       true,
      sends_whatsapp:     false,
      live_send_blocked:  true,
      success:            false,
      staff_user_id:      actorId,
      auth_mode:          resolvedAuthMode,
      elapsed_ms:         elapsed,
    });
    return sendJSON(res, 500, {
      ...buildSafeReviewDryRun500Body({
        error: 'open demo WhatsApp inbound dry-run failed',
        auth_mode: resolvedAuthMode,
        elapsed_ms: elapsed,
      }),
      open_demo: true,
    });
  }
}

function parseGuestSimulatorChain(body) {
  const src = body || {};
  const chain = src.chain || {};
  const review = src.review || chain;
  return {
    result: chain.result || review.result || null,
    availability: chain.availability || review.availability || null,
    quote: chain.quote || review.quote || null,
    payment_choice: chain.payment_choice || review.payment_choice || null,
  };
}

function guestSimulatorProductionBlocked() {
  return String(process.env.NODE_ENV || '').toLowerCase() === 'production';
}

// Route: POST /staff/bot/guest-simulator-create-hold-draft  (Stage 27w)
async function handleBotGuestSimulatorCreateHoldDraft(req, res, user, authMode) {
  const started = Date.now();
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  if (guestSimulatorProductionBlocked()) {
    return sendJSON(res, 403, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'Luna Guest Simulator writes are disabled in production',
    });
  }

  if (body.confirm_simulator_write !== true && body.source !== 'luna_guest_simulator') {
    return sendJSON(res, 400, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'confirm_simulator_write:true required for simulator hold/draft write',
    });
  }

  const { chain, planner } = buildGuestSimulatorWriteChain(body);
  if (!chain.result || !chain.payment_choice) {
    return sendJSON(res, 400, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'chain with result and payment_choice is required',
    });
  }

  const pc = chain.payment_choice || {};
  if (pc.payment_choice_ready !== true
    || pc.next_safe_step !== 'ready_for_hold_payment_draft') {
    return sendJSON(res, 400, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'payment_choice must be ready_for_hold_payment_draft before simulator write',
      write_block_reasons: ['payment_choice_not_ready_for_hold_payment_draft'],
    });
  }

  if (planner && planner.plan_status !== 'ready') {
    return sendJSON(res, 400, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'hold_payment_draft_plan must be ready before simulator write',
      write_block_reasons: ['planner_not_ready_for_write'],
    });
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId = user ? user.staff_user_id : 'dev-bot-guest-simulator-local';
  const hostHeader = String(req.headers.host || '');

  try {
    const writeOut = await runGuestHoldPaymentDraftWriteDryRunApproved(chain, {
      confirm_write: true,
      client_slug: String(body.client_slug || DEFAULT_CLIENT).trim(),
      guest_name: body.guest_name,
      guest_email: body.guest_email,
      guest_phone: body.guest_phone,
      env: process.env,
      host_header: hostHeader,
      source: 'luna_guest_simulator_27w',
      planner: planner || undefined,
    });

    const elapsed = Date.now() - started;
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot_guest_simulator_create_hold_draft',
      category: 'bot_guest_simulator',
      simulator: true,
      no_write_performed: writeOut.write_status !== 'created' && writeOut.write_status !== 'reused_existing',
      sends_whatsapp: false,
      live_send_blocked: true,
      success: writeOut.success === true,
      write_status: writeOut.write_status || null,
      staff_user_id: actorId,
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, writeOut.success ? 200 : 400, {
      ...writeOut,
      simulator: true,
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });
  } catch (_) {
    const elapsed = Date.now() - started;
    return sendJSON(res, 500, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      simulator: true,
      error: 'guest simulator hold/draft write failed',
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });
  }
}

// Route: POST /staff/bot/guest-simulator-create-stripe-test-link  (Stage 27w)
async function handleBotGuestSimulatorCreateStripeTestLink(req, res, user, authMode) {
  const started = Date.now();
  let body = {};
  try {
    body = JSON.parse((await readBody(req)) || '{}');
  } catch (_) {
    return send400(res, 'invalid or missing JSON body');
  }

  if (guestSimulatorProductionBlocked()) {
    return sendJSON(res, 403, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'Luna Guest Simulator Stripe links are disabled in production',
    });
  }

  if (body.confirm_simulator_stripe !== true && body.source !== 'luna_guest_simulator') {
    return sendJSON(res, 400, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'confirm_simulator_stripe:true required for simulator Stripe test link',
    });
  }

  const paymentDraftId = body.payment_draft_id != null ? String(body.payment_draft_id).trim() : '';
  if (!paymentDraftId) {
    return sendJSON(res, 400, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      error: 'payment_draft_id is required',
    });
  }

  const resolvedAuthMode = authMode || (STAFF_AUTH_REQUIRED ? 'session' : 'open');
  const actorId = user ? user.staff_user_id : 'dev-bot-guest-simulator-local';
  const hostHeader = String(req.headers.host || '');

  try {
    const linkOut = await runGuestStripeTestLinkCreateApproved({
      payment_draft_id: paymentDraftId,
      booking_id: body.booking_id,
      booking_code: body.booking_code,
      staff_operator: actorId,
      source: 'luna_guest_simulator_27w',
    }, {
      confirm_stripe_test_link: true,
      env: process.env,
      host_header: hostHeader,
    });

    const elapsed = Date.now() - started;
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:bot_guest_simulator_create_stripe_test_link',
      category: 'bot_guest_simulator',
      simulator: true,
      sends_whatsapp: false,
      live_send_blocked: true,
      stripe_link_created: linkOut.stripe_link_created === true,
      success: linkOut.success === true,
      staff_user_id: actorId,
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, linkOut.success ? 200 : 400, {
      ...linkOut,
      simulator: true,
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });
  } catch (_) {
    const elapsed = Date.now() - started;
    return sendJSON(res, 500, {
      success: false,
      sends_whatsapp: false,
      live_send_blocked: true,
      simulator: true,
      error: 'guest simulator Stripe test link failed',
      auth_mode: resolvedAuthMode,
      elapsed_ms: elapsed,
    });
  }
}

