// ─────────────────────────────────────────────────────────────────────────────
// Stage 7.7b — Conversation API handlers (read-only)
//
// All six handlers share the same safety contract:
//   • SELECT-only via staff-conversation-queries.js helpers
//   • client-scoped ($1 = client slug, $2 = UUID for per-conversation routes)
//   • audit entry per call with intent prefix api:conversation.*
//   • requireAuth enforced when STAFF_AUTH_REQUIRED=true (viewer minimum)
//   • no writes to any table (conversations / bookings / payments / handoffs / etc.)
//   • last_seen_at slide on auth_sessions is the only DB write (via loadAuthSession)
// ─────────────────────────────────────────────────────────────────────────────

function mapCustomerListRow(row) {
  const serviceType = row.last_service_type || '';
  const badges = [];
  if (row.is_booked) badges.push('booked');
  if (serviceType === 'surf_lesson') badges.push('lesson');
  if (serviceType === 'wetsuit' || serviceType === 'surfboard') badges.push('rental');
  if (row.has_open_handoff || row.needs_human) badges.push('needs_attention');
  let lastServiceSummary = null;
  if (serviceType) {
    const qty = row.last_service_quantity != null ? row.last_service_quantity : 1;
    const label = serviceType.replace(/_/g, ' ');
    lastServiceSummary = qty + ' ' + label;
  }
  return {
    phone: row.phone,
    conversation_id: row.conversation_id || null,
    display_name: row.display_name || null,
    email: row.email || null,
    language: row.language || null,
    last_contact_at: row.last_contact_at || null,
    needs_human: !!row.needs_human,
    conversation_stage: row.conversation_stage || null,
    booking_count: row.booking_count || 0,
    service_count: row.service_count || 0,
    last_service_summary: lastServiceSummary,
    last_check_in: row.last_check_in || null,
    last_service_date: row.last_service_date || row.last_service_date_detail || null,
    has_open_handoff: !!row.has_open_handoff,
    is_booked: !!row.is_booked,
    badges,
    last_message_preview: row.last_message_preview || null,
  };
}



function decodeAdminPathId(segment) {
  try { return decodeURIComponent(String(segment || '')); } catch (_) { return String(segment || ''); }
}

async function handleAdminConfig(query, res, user) {
  const started = Date.now();
  const clientSlug = (String(query.client || DEFAULT_CLIENT)).trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const locationId = normalizeSunsetLocationId(query.location);
  const resolved = isSunsetAdminDbReadEnabled()
    ? await resolveTenantBusinessConfigAsync(clientSlug, { locationId })
    : resolveTenantBusinessConfig(clientSlug, locationId);
  if (!resolved.ok) {
    appendAuditLog({
      ts: new Date().toISOString(),
      intent: 'api:admin.config',
      category: 'admin_api',
      client_slug: clientSlug,
      success: false,
      reason: resolved.reason,
      staff_user_id: user ? user.staff_user_id : null,
      elapsed_ms: Date.now() - started,
    });
    if (resolved.reason === 'unsupported_client') {
      return sendJSON(res, 403, { success: false, error: 'unsupported_client', client_slug: clientSlug });
    }
    return sendJSON(res, 404, { success: false, error: resolved.reason || 'not_found' });
  }

  const elapsed = Date.now() - started;
  appendAuditLog({
    ts: new Date().toISOString(),
    intent: 'api:admin.config',
    category: 'admin_api',
    client_slug: clientSlug,
    success: true,
    read_only: true,
    source: resolved.source,
    location_id: locationId,
    price_count: (resolved.prices || []).length,
    staff_user_id: user ? user.staff_user_id : null,
    elapsed_ms: elapsed,
  });

  const { ok, ...payload } = resolved;
  return sendJSON(res, 200, {
    success: true,
    ...payload,
    read_only: !isSunsetAdminWritesEnabled(),
    writes_enabled: isSunsetAdminWritesEnabled(),
    elapsed_ms: elapsed,
  });
}

async function sendAdminWriteGateFailure(res, gate) {
  return sendJSON(res, gate.status, gate.body);
}

