function isInactiveInboxBookingStatusServer(status) {
  const s = String(status || '').toLowerCase();
  return s === 'cancelled' || s === 'canceled' || s === 'expired';
}

function filterActiveInboxBookings(rows) {
  return (rows || []).filter((b) => !isInactiveInboxBookingStatusServer(b.booking_status));
}

function sanitizeConversationContextForInbox(row) {
  if (!row || !isInactiveInboxBookingStatusServer(row.booking_status)) return row;
  return {
    ...row,
    booking_id: null,
    booking_code: null,
    booking_status: null,
    booking_payment_status: null,
    check_in: null,
    check_out: null,
    guest_count: null,
    package_code: null,
    assigned_room_code: null,
    assigned_bed_code: null,
  };
}

async function handleConversationContext(convId, query, res, user) {
  const started    = Date.now();
  const clientSlug = (String(query.client || DEFAULT_CLIENT)).trim();
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const scope = resolveSunsetConversationScope(clientSlug, query);

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'api:conversation.context',
    category:        'conversation_api',
    client_slug:     clientSlug,
    location_id:     scope.locationId,
    conversation_id: convId,
    staff_user_id:   user ? user.staff_user_id : null,
  };

  let contextRow;
  let bookingRows;
  try {
    ({ contextRow, bookingRows } = await withPgClient(async (pg) => {
      const detailParams = conversationDetailQueryParams(clientSlug, convId, scope);
      const ctx = await pg.query(getConversationContextQuery(scope.queryOpts), detailParams);
      const bk = await pg.query(getConversationBookingsQuery(scope.queryOpts), detailParams);
      return { contextRow: ctx.rows[0] || null, bookingRows: bk.rows || [] };
    }));
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'query failed' });
  }

  const elapsed = Date.now() - started;
  if (!contextRow) {
    appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: elapsed });
    return send404(res);
  }

  const activeBookings = filterActiveInboxBookings(bookingRows);
  const context = sanitizeConversationContextForInbox(contextRow);

  appendAuditLog({
    ...auditBase,
    success: true,
    row_count: activeBookings.length || (context && context.booking_id ? 1 : 0),
    elapsed_ms: elapsed,
  });
  return sendJSON(res, 200, {
    success: true,
    context,
    bookings: activeBookings,
    elapsed_ms: elapsed,
  });
}

