// ─────────────────────────────────────────────────────────────────────────────
// Phase 23c.1 — Mark Meta handoff queue item reviewed
//
// POST /staff/inbox/handoffs/:id/review
//   Updates guest_message_events.normalized.handoff_review only.
//
// Safety: no staff_handoffs, no WhatsApp, no raw_payload mutation. Operator+ auth.
// ─────────────────────────────────────────────────────────────────────────────

async function handleInboxHandoffReview(eventId, req, res, user) {
  const started = Date.now();
  let body;
  try {
    body = JSON.parse(await readBody(req));
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const parsed = parseHandoffReviewInput(body);
  if (!parsed.ok) return send400(res, parsed.error);

  const clientSlug = parsed.input.client_slug;
  if (SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');

  const reviewedBy = user && (user.email || user.staff_user_id)
    ? String(user.email || user.staff_user_id)
    : 'unknown';

  const auditBase = {
    ts:            new Date().toISOString(),
    intent:        'action:api:inbox.handoff.review',
    category:      'inbox_handoff_review',
    client_slug:   clientSlug,
    event_id:      eventId,
    staff_user_id: user ? user.staff_user_id : null,
  };

  try {
    const result = await withPgClient((pg) => markGuestMessageEventHandoffReviewed(pg, {
      client_slug: clientSlug,
      event_id: eventId,
      reviewed_by: reviewedBy,
      review_note: parsed.input.review_note,
    }));

    const elapsed = Date.now() - started;

    if (!result.ok) {
      appendAuditLog({
        ...auditBase,
        success: false,
        error: result.error,
        elapsed_ms: elapsed,
      });
      return sendJSON(res, result.status || 500, {
        success: false,
        error: result.error || 'review failed',
      });
    }

    appendAuditLog({
      ...auditBase,
      success: true,
      already_reviewed: result.already_reviewed === true,
      elapsed_ms: elapsed,
    });

    return sendJSON(res, 200, {
      success: true,
      event_id: eventId,
      already_reviewed: result.already_reviewed === true,
      handoff_review: result.handoff_review,
      no_whatsapp: true,
      no_staff_handoffs_write: true,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({
      ...auditBase,
      success: false,
      error: err.message,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 500, { success: false, error: 'review failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Phase 23d — Staff Inbox explicit reply send
//
// POST /staff/inbox/send-reply
//   Delegates to evaluateGuestReplySendRouteWithPause (guest_message_sends audit path).
// ─────────────────────────────────────────────────────────────────────────────

async function handleInboxSendReply(req, res, user) {
  const started = Date.now();
  let body;
  try {
    body = JSON.parse(await readBody(req));
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const parsed = parseInboxSendReplyInput(body);
  if (!parsed.ok) return send400(res, parsed.error);

  const input = parsed.input;
  if (SQL_INJECT_RE.test(input.client_slug)) return send400(res, 'invalid client_slug');

  const actorId = user ? user.staff_user_id : null;
  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'action:api:inbox.send_reply',
    category:        'inbox_send_reply',
    client_slug:     input.client_slug,
    conversation_id: input.conversation_id,
    staff_user_id:   actorId,
  };

  try {
    const evaluated = await withPgClient(async (pg) => {
      let sendInput = { ...input };
      if (!sendInput.to) {
        const phone = await resolveConversationGuestPhone(pg, input.client_slug, input.conversation_id);
        if (!phone.ok) {
          return { error: phone.error, status: phone.status || 404 };
        }
        sendInput.to = phone.to;
      }
      const sendBody = buildStaffInboxGuestReplyBody(sendInput);
      const out = await evaluateGuestReplySendRouteWithPause(sendBody, { pg, env: process.env });
      const thread = await persistStaffInboxSentThreadMessage(pg, sendInput, out.result);
      return { sendBody, out, thread };
    });

    if (evaluated.error) {
      appendAuditLog({ ...auditBase, success: false, error: evaluated.error, elapsed_ms: Date.now() - started });
      return sendJSON(res, evaluated.status || 404, { success: false, error: evaluated.error });
    }

    const elapsed = Date.now() - started;
    const result = evaluated.out.result;
    const thread = evaluated.thread || {};

    appendAuditLog({
      ...auditBase,
      success:                      result.success === true,
      send_performed:               result.send_performed === true,
      sends_whatsapp:               result.sends_whatsapp === true,
      would_send_whatsapp:          result.would_send_whatsapp === true,
      send_kind:                    result.send_kind || 'staff_reply',
      idempotency_key:              result.idempotency_key || input.idempotency_key,
      blocked_reasons:              result.blocked_reasons || [],
      duplicate:                    result.duplicate === true,
      idempotent_replay:            result.idempotent_replay === true,
      guest_message_send_id:        result.guest_message_send_id || null,
      guest_message_send_status:    result.guest_message_send_status || null,
      thread_message_persisted:   thread.persisted === true,
      thread_message_id:            thread.message_id || null,
      elapsed_ms:                   elapsed,
    });

    return sendJSON(res, evaluated.out.status, {
      ...result,
      conversation_id: input.conversation_id,
      thread_message: thread.persisted || thread.duplicate ? {
        message_id: thread.message_id || null,
        persisted: thread.persisted === true,
        duplicate: thread.duplicate === true,
        whatsapp_message_id: thread.whatsapp_message_id || result.whatsapp_message_id || null,
      } : null,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({
      ...auditBase,
      success: false,
      error: err.message,
      elapsed_ms: Date.now() - started,
    });
    return sendJSON(res, 500, { success: false, error: 'send failed', detail: err.message });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Staff Portal — conversation needs_human toggle (conversations table only)
//
// POST /staff/conversations/:id/needs-human
//   Body: { client_slug, needs_human: boolean }
//
// Safety: updates conversations.needs_human only. No WhatsApp, staff_handoffs,
// bookings, payments, or Stripe. Operator+ session auth.
// ─────────────────────────────────────────────────────────────────────────────

async function handleConversationNeedsHuman(convId, req, res, user) {
  const started = Date.now();
  let body;
  try {
    body = JSON.parse(await readBody(req));
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  if (!clientSlug || SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (typeof body.needs_human !== 'boolean') return send400(res, 'needs_human boolean is required');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'action:api:conversation.needs_human',
    category:        'conversation_api',
    client_slug:     clientSlug,
    conversation_id: convId,
    staff_user_id:   user ? user.staff_user_id : null,
    needs_human:     body.needs_human,
  };

  try {
    const outcome = await withPgClient(async (pg) => {
      const prior = await pg.query(
        `SELECT conv.needs_human, conv.phone, conv.display_name, conv.metadata
           FROM conversations conv
           JOIN clients c ON c.id = conv.client_id
          WHERE c.slug = $1 AND conv.id = $2::uuid
          LIMIT 1`,
        [clientSlug, convId],
      );
      const priorRow = prior.rows[0];
      if (!priorRow) return { row: null };

      const wasNeedsHuman = priorRow.needs_human === true;
      const r = await pg.query(
        `UPDATE conversations conv
            SET needs_human = $3,
                updated_at = NOW(),
                metadata = CASE
                  WHEN $3 = TRUE AND conv.needs_human IS DISTINCT FROM TRUE THEN
                    COALESCE(conv.metadata, '{}'::jsonb)
                      || jsonb_build_object(
                        'needs_human_reason', to_jsonb('staff_manual_toggle'::text),
                        'luna_handoff_at', to_jsonb($4::text)
                      )
                  ELSE conv.metadata
                END
           FROM clients c
          WHERE conv.client_id = c.id
            AND c.slug = $1
            AND conv.id = $2::uuid
          RETURNING conv.id::text AS conversation_id, conv.needs_human`,
        [clientSlug, convId, body.needs_human, new Date().toISOString()],
      );
      const row = r.rows[0] || null;
      let staff_notification = null;
      if (row && body.needs_human === true && !wasNeedsHuman) {
        const handoffAt = new Date().toISOString();
        staff_notification = await maybeNotifyHumanNeeded(pg, process.env, {
          transitioned: true,
          handoff_event_key: handoffAt,
          client_slug: clientSlug,
          location_id: extractLocationFromMetadata(priorRow.metadata),
          conversation_id: row.conversation_id,
          guest_phone: priorRow.phone,
          guest_name: priorRow.display_name,
          reason: 'staff_manual_toggle',
        });
      }
      return { row, staff_notification };
    });

    const row = outcome.row;
    const elapsed = Date.now() - started;
    if (!row) {
      appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: elapsed });
      return send404(res);
    }

    appendAuditLog({ ...auditBase, success: true, elapsed_ms: elapsed });
    return sendJSON(res, 200, {
      success: true,
      conversation_id: row.conversation_id,
      needs_human: row.needs_human,
      staff_notification: outcome.staff_notification || null,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'update failed' });
  }
}

async function handleConversationResetAgentSession(convId, req, res, user) {
  const started = Date.now();
  const hostHeader = String(req.headers.host || '');

  if (!isStagingResetEnvironment(process.env, hostHeader)) {
    return sendJSON(res, 403, {
      success: false,
      error: 'staging_only',
      detail: 'Agent session reset is allowed only on staging/test environments.',
    });
  }

  let body;
  try {
    body = JSON.parse(await readBody(req));
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  if (!clientSlug || SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'action:api:conversation.reset_agent_session',
    category:        'conversation_api',
    client_slug:     clientSlug,
    conversation_id: convId,
    staff_user_id:   user ? user.staff_user_id : null,
  };

  try {
    const phoneRow = await withPgClient((pg) => pg.query(
      `SELECT c.phone
         FROM conversations c
         JOIN clients cl ON cl.id = c.client_id
        WHERE c.id = $1::uuid AND cl.slug = $2
        LIMIT 1`,
      [convId, clientSlug],
    ));
    if (!phoneRow.rows.length) {
      appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: Date.now() - started });
      return send404(res);
    }

    const guestPhone = phoneRow.rows[0].phone || null;
    let hermesSessionReset = { attempted: false, ok: false, reason: 'no_guest_phone' };
    if (guestPhone) {
      hermesSessionReset = await resetHermesGuestSession(guestPhone, { hard_delete: true });
    }

    const elapsed = Date.now() - started;
    appendAuditLog({
      ...auditBase,
      success: true,
      guest_phone: guestPhone,
      hermes_session_reset: hermesSessionReset,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      conversation_id: convId,
      guest_phone: guestPhone,
      hermes_session_reset: hermesSessionReset,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'reset failed' });
  }
}

// ─────────────────────────────────────────────────────────────────────────────
// Staff Portal — Fresh Start (Luna context reset; preserves messages + bookings)
//
// POST /staff/conversations/:id/reset-luna-context
//   Body: { client_slug }
//   Staging/test only — operator+ auth.
// ─────────────────────────────────────────────────────────────────────────────

async function handleConversationResetLunaContext(convId, req, res, user) {
  const started = Date.now();
  const hostHeader = String(req.headers.host || '');

  if (!isStagingResetEnvironment(process.env, hostHeader)) {
    return sendJSON(res, 403, {
      success: false,
      error: 'staging_only',
      detail: 'Fresh Start is allowed only on staging/test environments.',
    });
  }

  let body;
  try {
    body = JSON.parse(await readBody(req));
  } catch (_) {
    return send400(res, 'invalid JSON body');
  }

  const clientSlug = String(body.client_slug || DEFAULT_CLIENT).trim();
  if (!clientSlug || SQL_INJECT_RE.test(clientSlug)) return send400(res, 'invalid client_slug');
  if (!assertStaffClientAccess(user, clientSlug, res)) return;

  const auditBase = {
    ts:              new Date().toISOString(),
    intent:          'action:api:conversation.reset_luna_context',
    category:        'conversation_api',
    client_slug:     clientSlug,
    conversation_id: convId,
    staff_user_id:   user ? user.staff_user_id : null,
  };

  // On staging, Fresh Start is a true clean slate: clears context AND message history.
  // This matches the user expectation that "Fresh Start" means Luna has no memory of prior turns.
  const clearMessages = true;

  try {
    const result = await withPgClient((pg) => resetLunaConversationContext(pg, clientSlug, convId, { clearMessages }));
    const elapsed = Date.now() - started;
    if (!result.found) {
      appendAuditLog({ ...auditBase, success: false, error: 'not_found', elapsed_ms: elapsed });
      return send404(res);
    }

    let hermesSessionReset = { attempted: false, ok: false, reason: 'no_guest_phone' };
    let phoneEventsReset = { attempted: false };
    let bookingsCleared = { attempted: false };
    if (result.guest_phone) {
      hermesSessionReset = await resetHermesGuestSession(result.guest_phone, { hard_delete: true });
      // Also wipe the inbound webhook log (guest_message_events) + outbound
      // (guest_message_sends) for this number — otherwise that persisted history
      // re-seeds Luna's context and she still greets a "fresh" guest with the
      // usual order. This is what makes the reset a TRUE clean slate.
      const parsedPhone = parseResetLunaPhoneInput({ client_slug: clientSlug, phone: result.guest_phone });
      if (parsedPhone.ok) {
        try {
          phoneEventsReset = await withPgClient((pg) => resetLunaPhoneTestRows(pg, parsedPhone.input));
          phoneEventsReset.attempted = true;
        } catch (e) {
          phoneEventsReset = { attempted: true, ok: false, error: e.message };
        }
        // Testing wipe also cancels the guest's bookings (frees beds) so Luna
        // stops offering "your usual" from leftover test bookings.
        try {
          bookingsCleared = await withPgClient((pg) => cancelBookingsForPhone(pg, parsedPhone.input));
          bookingsCleared.attempted = true;
        } catch (e) {
          bookingsCleared = { attempted: true, ok: false, error: e.message };
        }
      }
    }

    appendAuditLog({
      ...auditBase,
      success: true,
      context_cleared: result.context_cleared,
      messages_deleted: result.messages_deleted,
      messages_preserved: result.messages_preserved,
      metadata_keys_cleared: result.metadata_keys_cleared,
      hermes_session_reset: hermesSessionReset,
      phone_events_reset: phoneEventsReset,
      bookings_cleared: bookingsCleared,
      elapsed_ms: elapsed,
    });
    return sendJSON(res, 200, {
      success: true,
      conversation_id: convId,
      context_cleared: result.context_cleared,
      messages_deleted: result.messages_deleted,
      messages_preserved: result.messages_preserved,
      metadata_keys_cleared: result.metadata_keys_cleared,
      hermes_session_reset: hermesSessionReset,
      phone_events_reset: phoneEventsReset,
      bookings_cleared: bookingsCleared,
      elapsed_ms: elapsed,
    });
  } catch (err) {
    appendAuditLog({ ...auditBase, success: false, error: err.message, elapsed_ms: Date.now() - started });
    return sendJSON(res, 500, { success: false, error: 'reset failed' });
  }
}

