// ─────────────────────────────────────────────────────────────────────────────
// GET /staff/auth/session — role + accessible clients for Staff Portal UI
// ─────────────────────────────────────────────────────────────────────────────

async function handleAuthSession(req, res) {
  if (!STAFF_AUTH_REQUIRED) {
    return sendJSON(res, 200, {
      success: true,
      auth_required: false,
      role: 'owner',
      email: null,
      display_name: null,
      clients: getAccessibleClients(null),
      client_profiles: buildClientProfilesMap(null),
      can_use_owner_insights: true,
    });
  }

  let user;
  try {
    user = await loadAuthSession(req);
  } catch (_) {
    return sendJSON(res, 500, { success: false, error: 'auth session lookup failed' });
  }

  if (!user) {
    return sendJSON(res, 401, {
      success: false,
      error: 'Authentication required. POST /staff/auth/login first.',
      auth_url: '/staff/auth/login',
    });
  }

  const resolvedRole = resolveStaffRole(user);
  const activeClient = String(user.client_slug || '').trim();
  if (!activeClient || !userCanAccessClient(user, activeClient)) {
    return sendJSON(res, 403, {
      success: false,
      error: 'session_client_access_denied',
      detail: 'Authenticated session client is missing or not allowed for this user.',
      active_client: activeClient || null,
    });
  }
  const sessionClients = getSessionScopedClients(user);
  return sendJSON(res, 200, {
    success: true,
    auth_required: true,
    role: resolvedRole,
    db_role: user.role,
    email: user.email,
    display_name: user.display_name || null,
    active_client: activeClient,
    clients: sessionClients,
    client_profiles: buildSessionClientProfilesMap(user),
    can_use_owner_insights: canUseOwnerInsights(user),
  });
}

